INSERT INTO `destinations` VALUES (1, 'Bãi Dài Cam Ranh', 'Bãi biển hoang sơ với vẻ đẹp tự nhiên, lý tưởng để thư giãn và tắm biển', 'Khánh Hòa', 'Khánh Hòa', 'Khánh Hòa', 12.0616, 109.2052, 'beach', '["https://www.uncovervietnam.com/wp-content/uploads/2021/06/bai-dai-beach-cam-ranh-vietnam.jpg"]', 4.8, 548, '00:00', '23:59', 0, '["biển","vui chơi","chụp ảnh","nghĩ dưỡng"]');
INSERT INTO `destinations` VALUES (2, 'Tháp Bà Ponagar', 'Công trình kiến trúc Chăm cổ, nơi du khách có thể tìm hiểu về lịch sử và văn hóa Chăm', 'Khánh Hòa', 'Khánh Hòa', 'Khánh Hòa', 12.26528, 109.1953, 'historical', '["https://tse4.mm.bing.net/th?id=OIP.OHY4mpZ7m_uKpGiC1e9D8wHaF7&pid=Api&P=0&h=220"]', 3.6, 1, '06:00', '17:30', 30000, '["tham quan","tháp","chụp ảnh","di tích","văn hóa"]');
INSERT INTO `destinations` VALUES (3, 'Thành cổ Diên Khánh', 'Di tích lịch sử với kiến trúc thành cổ độc đáo, được xây dựng từ thời Nguyễn.', 'Khánh Hòa', 'Khánh Hòa', 'Khánh Hòa', 12.254, 109.106, 'historical', '["https://tse2.mm.bing.net/th?id=OIP.BzA87w8zdYgM0o41HtKQCQHaFj&pid=Api&P=0&h=220"]', 4.5, 719, '07:00', '17:00', 0, '["tham quan","di tích","lịch sử","chụp ảnh","văn hóa"]');
INSERT INTO `destinations` VALUES (4, 'VinWonders Nha Trang', 'Công viên giải trí trên đảo Hòn Tre, nổi bật với nhiều trò chơi và hoạt động hấp dẫn.', 'Khánh Hòa', 'Khánh Hòa', 'Khánh Hòa', 12.21673, 109.23996, 'beach', '["https://tse1.mm.bing.net/th?id=OIP.5z6-9r5crvDbj01RkeQO2gHaDv&pid=Api&P=0&h=220"]', 4.6, 690, '08:30', '20:00', 1050000, '["công viên","vui chơi","giải trí","chụp ảnh"]');
INSERT INTO `destinations` VALUES (5, 'Suối Ba Hồ', 'Gồm ba hồ nước trong xanh nằm trên núi, thích hợp cho trekking và tắm suối', 'Khánh Hòa', 'Khánh Hòa', 'Khánh Hòa', 12.3725, 109.1218, 'nature', '["https://cdn1.nhatrangtoday.vn/images/photos/kdl-ba-ho-nha-trang-2.jpg"]', 4.3, 374, '07:00', '17:00', 0, '["suối","chụp ảnh","vui chơi"]');
INSERT INTO `destinations` VALUES (6, 'Đảo Phú Quốc ', 'Là điểm du lịch nổi tiếng nhất Kiên Giang, được mệnh danh là "Đảo Ngọc" với nhiều bãi biển đẹp và dịch vụ cao cấp', 'Kiên Giang', 'Kiên Giang', 'Kiên Giang', 10.2899, 103.984, 'food', '["https://vietnam.travel/sites/default/files/inline-images/du-lich-phu-quoc-thang-10-.jpeg"]', 4.8, 124, '06:00', '22:00', 0, '["đảo","biển","chụp ảnh","nghĩ dưỡng","vui chơi","ăn uống"]');
INSERT INTO `destinations` VALUES (7, 'Biển Mũi Nai', 'Bãi biển hiền hòa, nơi lý tưởng để thư giãn và ngắm cảnh hoàng hôn', 'Kiên Giang', 'Kiên Giang', 'Kiên Giang', 10.383, 104.48, 'beach', '["https://tse1.mm.bing.net/th?id=OIP.Ya_axd_TszOeEk3QppjKMwHaFj&pid=Api&P=0&h=220"]', 4.7, 221, '00:00', '23:59', 0, '["biển","vui chơi","chụp ảnh","nghĩ dưỡng"]');
INSERT INTO `destinations` VALUES (8, 'Chùa Láng Cát', 'Ngôi chùa cổ kính mang đậm dấu ấn Phật giáo.', 'Kiên Giang', 'Kiên Giang', 'Kiên Giang', 10.032226, 105.088104, 'religious', '["https://tse4.mm.bing.net/th?id=OIP.8FZLE40kihfcd4nTAkjEZQHaFj&pid=Api&P=0&h=220"]', 4.4, 233, '07:00', '18:00', 0, '["chùa","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (9, 'Vườn quốc gia U Minh Thượng', 'Rừng ngập mặn với hệ sinh thái phong phú, là nơi lý tưởng để khám phá thiên nhiên hoang dã và tham quan bằng thuyền', 'Kiên Giang', 'Kiên Giang', 'Kiên Giang', 9.6224, 105.0869, 'nature', '["https://nucuoimekong.com/wp-content/uploads/vuon-quoc-gia-u-minh-thuong-toan-canh.jpg"]', 4.6, 172, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (10, 'Mộ chị Sứ', 'Khu di tích lịch sử nổi tiếng, gắn liền với cuộc kháng chiến chống Pháp.', 'Kiên Giang', 'Kiên Giang', 'Kiên Giang', 10.026488, 105.051011, 'historical', '["https://tse2.mm.bing.net/th?id=OIP.TzRGCJsnEfeGXnPqQQFTLgHaFj&pid=Api&P=0&h=220"]', 4.4, 896, '07:00', '17:00', 0, '["di tích","lịch sử"]');
INSERT INTO `destinations` VALUES (11, 'Nhà Thờ Gỗ Kon Tum', 'Một biểu tượng của Kon Tum mang kiến trúc độc đáo pha trộn giữa phong cách Roman và nét văn hóa Tây Nguyên', 'Kon Tum', 'Kon Tum', 'Kon Tum', 14.3494, 108.0076, 'religious', '["https://tse1.mm.bing.net/th?id=OIP.RzH7A5ksQ9692U5WrfW10gHaFu&pid=Api&P=0&h=220"]', 4.4, 794, '07:00', '18:00', 0, '["tôn giáo","tham quan","chụp ảnh","văn hóa"]');
INSERT INTO `destinations` VALUES (12, 'Cầu Treo Kon Klor', 'Cây cầu treo lớn và đẹp nhất ở Kon Tum, bắc qua sông Đăk Bla, được bao quanh bởi những cánh đồng lúa và núi rừng xanh mát', 'Kon Tum', 'Kon Tum', 'Kon Tum', 14.3434, 108.0246, 'nature', '["https://kontumtrip.com/wp-content/uploads/2021/03/cau-treo-kon-klor-%E2%80%98dai-lua-mau-cam-ben-dong-dak-bla-1615296514-600x600.jpg"]', 4.6, 593, '07:00', '17:00', 0, '["cầu treo","chụp ảnh","tham quan"]');
INSERT INTO `destinations` VALUES (13, 'Vườn Quốc Gia Chư Mom Ray', 'Là khu bảo tồn thiên nhiên lớn nhất Việt Nam, nổi bật với hệ sinh thái phong phú, những cánh rừng nguyên sinh và động vật quý hiếm', 'Kon Tum', 'Kon Tum', 'Kon Tum', 14.618, 107.691, 'nature', '["https://tse3.mm.bing.net/th?id=OIP.QOcHIfacwNqsrxuaNNlZ4gHaEr&pid=Api&P=0&h=220"]', 4.5, 893, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (14, 'Đỉnh Ngọc Linh', 'Ngọn núi cao nhất ở Tây Nguyên, thuộc dãy Trường Sơn, là nơi sinh sống của nhiều loài động thực vật quý hiếm.', 'Kon Tum', 'Kon Tum', 'Kon Tum', 15.0667, 107.9833, 'nature', '["https://tse4.mm.bing.net/th?id=OIP.yYzLVlMeUpU6vk_7d0gLjAHaE8&pid=Api&P=0&h=220"]', 3.3, 1, '07:00', '17:00', 0, '["núi","thám hiểm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (15, 'Thác Đắk Tô', 'Nằm gần thị trấn Đắk Tô, thác nước này hoang sơ và yên bình, là địa điểm lý tưởng để thư giãn giữa thiên nhiên', 'Kon Tum', 'Kon Tum', 'Kon Tum', 14.347003, 107.979174, 'nature', '["https://cdn.tgdd.vn/Files/2023/09/11/1546829/du-lich-dak-to-kon-tum-di-dau-5-dia-diem-duoc-yeu-thich-202309112252096063.jpg"]', 4.3, 803, '07:00', '17:00', 0, '["thác","suối","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (16, 'Đèo Ô Quy Hồ', 'Một trong "Tứ đại đỉnh đèo" của Tây Bắc, Đèo Ô Quy Hồ nối liền Lào Cai và Lai Châu, nổi tiếng với cảnh sắc tuyệt đẹp và độ cao hùng vĩ', 'Lai Châu ', 'Lai Châu', 'Lai Châu ', 22.35, 103.76, 'nature', '["https://www.kynghidongduong.vn/userfiles/images/Vietnam/Sapa/deo-o-quy-ho-sapa-kynghidongduong.vn%20(02).jpg"]', 4.5, 329, '07:00', '17:00', 0, '["đèo","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (17, 'Đỉnh Pu Ta Leng', 'Đỉnh núi cao thứ hai Việt Nam (3.049m), thuộc dãy Hoàng Liên Sơn, được mệnh danh là "nóc nhà thứ hai" của Đông Dương.', 'Lai Châu ', 'Lai Châu', 'Lai Châu ', 22.4167, 103.55, 'nature', '["https://tse4.mm.bing.net/th?id=OIP.BiJgl7PpikStQvCnsbFBnQHaEc&pid=Api&P=0&h=220"]', 4.6, 489, '07:00', '17:00', 0, '["núi","thám hiểm","chụp ảnh","khám phá"]');
INSERT INTO `destinations` VALUES (18, 'Cánh đồng Mường Than', 'Vào mùa lúa chín, cánh đồng Mường Than rực rỡ sắc vàng, tạo nên một bức tranh thiên nhiên thơ mộng', 'Lai Châu ', 'Lai Châu', 'Lai Châu ', 22.413846, 103.442792, 'checkin', '["https://tse2.mm.bing.net/th?id=OIP.9LboGnBOwneYQW4KMBKl9gHaEK&pid=Api&P=0&h=220"]', 4.7, 145, '00:00', '23:59', 0, '["cánh đồng","chụp ảnh","tham quan"]');
INSERT INTO `destinations` VALUES (19, 'Hồ Thủy Điện Lai Châu', 'Hồ nước nhân tạo khổng lồ được tạo nên từ công trình Thủy điện Lai Châu, nằm giữa khung cảnh núi non thơ mộng.', 'Lai Châu ', 'Lai Châu', 'Lai Châu ', 22.384118, 103.515252, 'nature', '["https://tse2.mm.bing.net/th?id=OIP.l_QHXHqnrJUG2mNIawZdzAHaFj&pid=Api&P=0&h=220"]', 4.5, 420, '07:00', '17:00', 0, '["hồ thủy điện","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (20, 'Chợ phiên Sìn Hồ', 'Nơi diễn ra các hoạt động mua bán nhộn nhịp của các dân tộc Thái, H’Mông, Dao, Lự...', 'Lai Châu ', 'Lai Châu', 'Lai Châu ', 22.3667, 103.2333, 'food', '["https://tse3.mm.bing.net/th?id=OIP.DttHClSeqyAUJH2yDY5JVAHaE7&pid=Api&P=0&h=220"]', 4.3, 765, '06:00', '22:00', 0, '["chợ","ăn uống","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (21, 'Hồ Xuân Hương', 'Biểu tượng của Đà Lạt, hồ nằm ngay trung tâm thành phố, bao quanh bởi rừng thông và những vườn hoa.', 'Lâm Đồng', 'Lâm Đồng', 'Lâm Đồng', 11.9404, 108.4419, 'nature', '["https://tse3.mm.bing.net/th?id=OIP.chmIO_bl-TWTEivpGFWdCAHaFj&pid=Api&P=0&h=220"]', 4.7, 286, '07:00', '17:00', 0, '["Hồ","chụp ảnh","tham quan","vui chơi"]');
INSERT INTO `destinations` VALUES (22, 'Thiền Viện Trúc Lâm', 'Một thiền viện nổi tiếng tọa lạc gần Hồ Tuyền Lâm, mang kiến trúc thanh tịnh và không gian yên bình.', 'Lâm Đồng', 'Lâm Đồng', 'Lâm Đồng', 11.9049, 108.4388, 'religious', '["https://tse1.mm.bing.net/th?id=OIP.0pUp5Fpj3xerMHL6wzKj_QHaFj&pid=Api&P=0&h=220"]', 4.6, 1, '07:00', '18:00', 0, '["chùa","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (23, 'Chợ Đêm Đà Lạt', 'Chợ đêm Đà Lạt là nơi bạn có thể thưởng thức đặc sản như bánh tráng nướng, sữa đậu nành và mua quà lưu niệm.', 'Lâm Đồng', 'Lâm Đồng', 'Lâm Đồng', 11.9438, 108.4373, 'food', '["https://tse3.mm.bing.net/th?id=OIP.nBiR1UiYs6NlbrXhm_FL5wHaE6&pid=Api&P=0&h=220"]', 4.8, 987, '06:00', '22:00', 0, '["chợ","ăn uống","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (24, 'Dinh Bảo Đại', 'Một trong ba dinh thự của vua Bảo Đại tại Đà Lạt, mang phong cách kiến trúc Pháp tinh tế.', 'Lâm Đồng', 'Lâm Đồng', 'Lâm Đồng', 11.9306, 108.4284, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.FGJV3cBpn9MxjuFGoEEKZAHaE8&pid=Api&P=0&h=220"]', 4.5, 317, '07:00', '17:00', 0, '["di tích","lịch sử","văn hóa","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (25, 'Thác Voi', 'Tọa lạc ở Nam Ban, thác Voi hùng vĩ và hoang sơ, là nơi lý tưởng cho những ai yêu thích khám phá thiên nhiên.', 'Lâm Đồng', 'Lâm Đồng', 'Lâm Đồng', 11.8301, 108.3551, 'nature', '["https://agotourist.com/wp-content/uploads/2022/05/thac-voi-duoc-chung-nhan-la-thang-canh-quoc-gia.jpg"]', 4.1, 2, '07:00', '17:00', 0, '["thác","suối","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (26, 'Động Tam Thanh', 'Được mệnh danh là "Đệ nhất bát cảnh Xứ Lạng"các nhũ đá kỳ thú và nhiều di tích cổ như tượng Phật A Di Đà cao 2m được tạc từ thế kỷ 15.', 'Lạng Sơn', 'Lạng Sơn', 'Lạng Sơn', 21.855, 106.7586, 'historical', '["https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/03/Tam-Thanh.jpg"]', 4.2, 885, '07:00', '17:00', 0, '["động","tham quan","thám hiểm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (27, 'Chợ Đông Kinh', 'Là trung tâm thương mại lớn nhất ở Lạng Sơn, nổi tiếng với các mặt hàng phong phú', 'Lạng Sơn', 'Lạng Sơn', 'Lạng Sơn', 21.8526, 106.761, 'food', '["https://tse2.mm.bing.net/th?id=OIP.jIAxzffR49430SWWKToE6wHaEx&pid=Api&P=0&h=220"]', 4.5, 56, '06:00', '22:00', 0, '["chợ","ăn uống","tham quan","văn hóa","mua sắm"]');
INSERT INTO `destinations` VALUES (28, 'Cửa khẩu Hữu Nghị', 'Đây là cửa khẩu quốc tế lớn giữa Việt Nam và Trung Quốc, nằm trên tuyến quốc lộ 1A.', 'Lạng Sơn', 'Lạng Sơn', 'Lạng Sơn', 21.9678, 106.7121, 'culture', '["https://tse1.mm.bing.net/th?id=OIP.Wf6JQTisUsMbq6-2euQeKQHaFj&pid=Api&P=0&h=220"]', 4.7, 255, '07:00', '17:00', 0, '["tham quan","mua sắm","văn hóa","chụp ảnh"]');
INSERT INTO `destinations` VALUES (29, 'Đèo Bông Lau', 'Là một cung đèo đẹp với những khúc cua uốn lượn và khung cảnh thiên nhiên ngoạn mục.', 'Lạng Sơn', 'Lạng Sơn', 'Lạng Sơn', 21.872288, 106.770772, 'checkin', '["https://tse4.mm.bing.net/th?id=OIP.bjd29nTPNt90j6mM3SC0qAHaEX&pid=Api&P=0&h=220"]', 3.4, 1, '00:00', '23:59', 0, '["tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (30, 'Chùa Tiên ', 'Chùa Tiên nằm trên núi Đại Tượng, gắn liền với nhiều câu chuyện huyền thoại và mang đậm dấu ấn Phật giáo.', 'Lạng Sơn', 'Lạng Sơn', 'Lạng Sơn', 21.847, 106.761, 'religious', '["https://tse2.mm.bing.net/th?id=OIP.FxWdyg8edX5JSQPZPlZ8dwHaE7&pid=Api&P=0&h=220"]', 4.3, 477, '07:00', '18:00', 0, '["chùa","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (31, 'Đỉnh Núi Fansipan', 'Fansipan được mệnh danh là “Nóc nhà Đông Dương” với độ cao 3.147m.', 'Lào Cai', 'Lào Cai', 'Lào Cai', 22.3033, 103.775, 'nature', '["https://limtravel.vn/wp-content/uploads/2020/10/tour-leo-nui-fansipan-3-1.jpg"]', 4.8, 843, '07:00', '17:00', 0, '["núi","tham quan","thám hiểm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (32, 'Cổng Trời Ô Quy Hồ', 'Đèo Ô Quy Hồ là một trong "Tứ đại đỉnh đèo" của Tây Bắc, nối liền Lào Cai và Lai Châu.', 'Lào Cai', 'Lào Cai', 'Lào Cai', 22.3525, 103.7712, 'nature', '["https://media.techcity.cloud/vietnam.vn/2023/09/cong-troi-o-quy-ho-sapa_26-09-2022_175234433.jpg"]', 4.5, 787, '07:00', '17:00', 0, '["đèo","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (33, 'Chợ phiên Bắc Hà', 'Chợ phiên Bắc Hà nổi tiếng với các mặt hàng thổ cẩm, nông sản và các món ăn đặc trưng của người dân tộc H’Mông, Dao.', 'Lào Cai', 'Lào Cai', 'Lào Cai', 22.5367, 104.2911, 'food', '["https://tse1.mm.bing.net/th?id=OIP.4K8zaZgInJkSkftXRLz_-wHaFA&pid=Api&P=0&h=220"]', 4.3, 897, '06:00', '22:00', 0, '["chợ","tham quan","ăn uống","mua sắm"]');
INSERT INTO `destinations` VALUES (34, 'Thác Tình Yêu', 'Là một điểm đến lãng mạn với dòng nước trong xanh chảy qua rừng nguyên sinh.', 'Lào Cai', 'Lào Cai', 'Lào Cai', 22.3386, 103.7809, 'nature', '["https://docmiendatnuoc.com/wp-content/uploads/2019/07/thac-tinh-yeu-sapa-1.jpg"]', 4.2, 1, '07:00', '17:00', 0, '["thác","suối","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (35, 'Đền Thượng', 'Là nơi thờ Trần Hưng Đạo, vị tướng tài ba trong lịch sử Việt Nam.', 'Lào Cai', 'Lào Cai', 'Lào Cai', 22.5011, 103.9576, 'religious', '["https://52hz.vn/wp-content/uploads/2023/01/31-den-thuong-lao-cai-chinh-dien.jpg"]', 4.3, 798, '07:00', '18:00', 0, '["đền","tham quan","chụp ảnh","lịch sử"]');
INSERT INTO `destinations` VALUES (36, 'Làng nổi Tân Lập', 'Là khu rừng tràm ngập nước rộng lớn, nổi tiếng với con đường xuyên rừng dài gần 5km.', 'Long An', 'Long An', 'Long An', 10.7378, 105.9677, 'nature', '["https://disantrangan.vn/wp-content/uploads/2021/05/lang_noi_tan_lap_18-1600x1066.jpg"]', 3.5, 1, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (37, 'Nhà cổ Trăm Cột', 'Là một ngôi nhà cổ độc đáo với 120 cột gỗ quý được chạm khắc tinh xảo.', 'Long An', 'Long An', 'Long An', 10.5908, 106.5042, 'historical', '["https://tse4.mm.bing.net/th?id=OIP.E5QmqrexARskIuVpHN_f3wHaFR&pid=Api&P=0&h=220"]', 4.5, 456, '07:00', '17:00', 0, '["tham quan","chụp ảnh","văn hóa","di tích"]');
INSERT INTO `destinations` VALUES (38, 'Chùa Tôn Thạnh', 'Ngôi chùa này là nơi cụ Nguyễn Đình Chiểu từng ở và sáng tác bài văn tế "Văn tế nghĩa sĩ Cần Giuộc".', 'Long An', 'Long An', 'Long An', 10.662741, 106.240049, 'religious', '["https://tse4.mm.bing.net/th?id=OIP.4g4eE5ZOp5g9_9DlwrJZrwHaEw&pid=Api&P=0&h=220"]', 4.6, 370, '07:00', '18:00', 0, '["chùa","tham quan","văn hóa"]');
INSERT INTO `destinations` VALUES (39, 'Sông Vàm Cỏ ', 'Hai dòng sông lớn chảy qua Long An tạo nên vẻ đẹp sông nước đặc trưng.', 'Long An', 'Long An', 'Long An', 10.72667, 106.219527, 'checkin', '["https://tse2.mm.bing.net/th?id=OIP.ZorRqKgh2xWA02dJByJFpQHaEK&pid=Api&P=0&h=220"]', 4.2, 448, '00:00', '23:59', 0, '["sông","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (40, 'Chợ đêm Tân An', 'Là nơi lý tưởng để thưởng thức ẩm thực địa phương và mua sắm các đặc sản Long An', 'Long An', 'Long An', 'Long An', 10.687538, 106.287372, 'food', '["https://tse1.mm.bing.net/th?id=OIP.pqR8Xckg_RDQQn2YZLpmegHaEK&pid=Api&P=0&h=220"]', 4.7, 785, '06:00', '22:00', 0, '["chợ","tham quan","ăn uống","mua sắm"]');
INSERT INTO `destinations` VALUES (41, 'Nhà thờ Phú Nhai', 'Là một trong những nhà thờ lớn và cổ kính nhất Việt Nam, mang phong cách kiến trúc Gothic đặc sắc.', 'Nam Đinh', 'Nam Đinh', 'Nam Đinh', 15.972844, 105.956831, 'religious', '["https://photo-cms-vovworld.zadn.vn/w500/Uploaded/vovworld/yzfsm/2020_01_10/kpvn014_AXJU.jpg"]', 4.5, 357, '07:00', '18:00', 0, '["nhà thờ","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (42, 'Đền Trần', 'Nằm tại phường Lộc Vượng, thành phố Nam Định, đền Trần thờ các vua nhà Trần, gắn liền với lịch sử hào hùng của triều đại này.', 'Nam Đinh', 'Nam Đinh', 'Nam Đinh', 20.4226, 106.161, 'religious', '["https://tse3.mm.bing.net/th?id=OIP.CNccGQUyOTTpBixYdfCL5wHaE7&pid=Api&P=0&h=220"]', 4.3, 741, '07:00', '18:00', 0, '["đền","tham quan","chụp ảnh","lịch sử"]');
INSERT INTO `destinations` VALUES (43, 'Vườn quốc gia Xuân Thủy', 'Đây là khu bảo tồn thiên nhiên nằm ở huyện Giao Thủy, thuộc vùng hạ lưu sông Hồng.', 'Nam Đinh', 'Nam Đinh', 'Nam Đinh', 20.2561, 106.56, 'nature', '["https://tse4.mm.bing.net/th?id=OIP.DfkyYRBhnuiU-rR43dUeJAHaFS&pid=Api&P=0&h=220"]', 4.6, 391, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (44, 'Chợ Viềng', 'Là phiên chợ đặc biệt chỉ diễn ra một lần trong năm vào đêm mùng 7, rạng sáng mùng 8 tháng Giêng âm lịch.', 'Nam Đinh', 'Nam Đinh', 'Nam Đinh', 16.00939, 105.974686, 'food', '["https://phuday.com/wp-content/uploads/2020/01/cho-vieng-phu-day-nam-dinh-768x432.jpg"]', 4.6, 477, '06:00', '22:00', 0, '["chợ","tham quan","ăn uống","mua sắm"]');
INSERT INTO `destinations` VALUES (45, 'Hồ Vị Xuyên', 'Hồ nằm trong thành phố Nam Định, là một địa điểm lý tưởng để thư giãn, đi dạo, thưởng thức không gian xanh và yên bình.', 'Nam Đinh', 'Nam Đinh', 'Nam Đinh', 16.012437, 106.030567, 'nature', '["https://tse3.mm.bing.net/th?id=OIP.mrQZh6uVh3jWDHuvlXNjHwHaFj&pid=Api&P=0&h=220"]', 4.5, 190, '07:00', '17:00', 0, '["hồ","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (46, 'Làng Sen', 'Là một ngôi nhà tranh đơn sơ, giếng Cốc, và những kỷ vật gắn liền với thời thơ ấu của Bác.', 'Nghệ An', 'Nghệ An', 'Nghệ An', 18.832, 105.4785, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.3gHvKfVcK1kovpdqLo2OtwAAAA&pid=Api&P=0&h=220"]', 4.7, 84, '07:00', '17:00', 0, '["lịch sử","tham quan","di tích","văn hóa"]');
INSERT INTO `destinations` VALUES (47, 'Bãi biển Cửa Lò', 'Một trong những bãi biển đẹp nhất miền Trung, Cửa Lò thu hút du khách với cát trắng mịn, nước biển trong xanh và hải sản tươi ngon.', 'Nghệ An', 'Nghệ An', 'Nghệ An', 18.8177, 105.721, 'beach', '["https://tse1.mm.bing.net/th?id=OIP.hzSUzcdB1G9w2e52jf6HHAHaD-&pid=Api&P=0&h=220"]', 4.6, 95, '00:00', '23:59', 0, '["biển","vui chơi","chụp ảnh","nghĩ dưỡng"]');
INSERT INTO `destinations` VALUES (48, 'Khu di tích Truông Bồn', 'Là một di tích lịch sử quan trọng, nơi tưởng nhớ các anh hùng liệt sĩ đã hy sinh trong cuộc kháng chiến chống Mỹ.', 'Nghệ An', 'Nghệ An', 'Nghệ An', 18.7707, 105.5038, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.XdhDVeaTTt6NYVOiOOHpSAHaEK&pid=Api&P=0&h=220"]', 4.5, 477, '07:00', '17:00', 0, '["lịch sử","tham quan","di tích","văn hóa"]');
INSERT INTO `destinations` VALUES (49, 'Đồi chè Thanh Chương', 'Được mệnh danh là "đảo chè", đồi chè Thanh Chương là địa điểm lý tưởng để chụp ảnh và tận hưởng không khí trong lành.', 'Nghệ An', 'Nghệ An', 'Nghệ An', 18.731, 105.3667, 'beach', '["https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/08/doi-che-thanh-chuong.jpg"]', 4.5, 640, '00:00', '23:59', 0, '["đồi","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (50, 'Hang Thẩm Ồm', 'Là một hang động lớn, với nhiều thạch nhũ kỳ ảo, hình thù độc đáo.', 'Nghệ An', 'Nghệ An', 'Nghệ An', 18.690418, 105.704465, 'nature', '["https://tse1.mm.bing.net/th?id=OIP.dqYi6NCHovDo0Srdp6NMwQHaE8&pid=Api&P=0&h=220"]', 4.3, 984, '07:00', '17:00', 0, '["hang động","thám hiểm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (51, 'Tràng An', 'Là Di sản Văn hóa và Thiên nhiên thế giới, Tràng An nổi bật với cảnh núi non hùng vĩ và hệ thống hang động độc đáo.', 'Ninh Bình', 'Ninh Bình', 'Ninh Bình', 20.2529, 105.9187, 'historical', '["https://dulichninhbinh.com.vn/mypicture/images/2020/10/Trang-An-2.jpg"]', 4.6, 620, '07:00', '16:30', 250000, '["tham quan","chụp ảnh","văn hóa","di tích"]');
INSERT INTO `destinations` VALUES (52, 'Tam Cốc', 'Được mệnh danh là "vịnh Hạ Long trên cạn", với cảnh sắc thiên nhiên tuyệt đẹp của núi đá vôi, cánh đồng lúa, và dòng sông Ngô Đồng.', 'Ninh Bình', 'Ninh Bình', 'Ninh Bình', 20.215, 105.9366, 'beach', '["https://tse2.mm.bing.net/th?id=OIP.e1wQWQ7OBNItnMauRi6uwgHaEo&pid=Api&P=0&h=220"]', 4.7, 676, '07:00', '17:00', 120000, '["tham quan","chụp ảnh","văn hóa","di tích"]');
INSERT INTO `destinations` VALUES (53, 'Cố đô Hoa Lư', 'Là kinh đô của nước Đại Cồ Việt dưới triều Đinh và Tiền Lê, Hoa Lư lưu giữ nhiều di tích lịch sử quan trọng', 'Ninh Bình', 'Ninh Bình', 'Ninh Bình', 20.2827, 105.9064, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.HKYPnw54Dsgh0XZTqKPKyQHaE7&pid=Api&P=0&h=220"]', 4.5, 554, '07:00', '17:00', 20000, '["lịch sử","tham quan","di tích","văn hóa"]');
INSERT INTO `destinations` VALUES (54, 'Vườn quốc gia Cúc Phương', 'Là vườn quốc gia đầu tiên của Việt Nam với hệ động thực vật phong phú, những cây cổ thụ nghìn năm tuổi và các hang động tiền sử.', 'Ninh Bình', 'Ninh Bình', 'Ninh Bình', 20.35, 105.6, 'nature', '["https://tse2.mm.bing.net/th?id=OIP.V7YRaVEqqQndhpDcL0tNSQHaD8&pid=Api&P=0&h=220"]', 4.8, 115, '07:00', '17:00', 60000, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (55, 'Hồ Đồng Chương', 'Hồ Đồng Chương là một hồ nước tự nhiên nằm giữa rừng thông, rất yên bình và thơ mộng.', 'Ninh Bình', 'Ninh Bình', 'Ninh Bình', 20.301533, 105.977116, 'nature', '["https://dulichdiaphuong.com/imgs/tinh-ninh-binh/ho-dong-chuong.jpg"]', 4.3, 505, '07:00', '17:00', 0, '["Hồ","chụp ảnh","tham quan","vui chơi"]');
INSERT INTO `destinations` VALUES (56, 'Vịnh Vĩnh Hy', 'Một trong bốn vịnh đẹp nhất Việt Nam, Vĩnh Hy gây ấn tượng bởi nước biển trong xanh, bãi cát trắng mịn, và các rạn san hô rực rỡ.', 'Ninh Thuận', 'Ninh Thuận', 'Ninh Thuận', 11.719, 109.19, 'beach', '["https://tse1.mm.bing.net/th?id=OIP.1gJ08quIQVapIDmYLV1GRgHaE7&pid=Api&P=0&h=220"]', 4.6, 767, '00:00', '23:59', 0, '["vịnh","tham quan","chụp ảnh","nghĩ dưỡng","vui chơi"]');
INSERT INTO `destinations` VALUES (57, 'Vườn quốc gia Núi Chúa', 'Là khu bảo tồn thiên nhiên với hệ sinh thái rừng khô hạn độc đáo, được UNESCO công nhận là Khu dự trữ sinh quyển thế giới.', 'Ninh Thuận', 'Ninh Thuận', 'Ninh Thuận', 11.736, 109.174, 'nature', '["https://media.mia.vn/uploads/blog-du-lich/vuon-quoc-gia-nui-chua-khu-du-tru-sinh-quyen-moi-cua-the-gioi-1-1658800083.jpg"]', 4.7, 505, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (58, 'Tháp Po Klong Garai', 'Đây là nơi thờ vua Po Klong Garai, thể hiện kiến trúc và nghệ thuật điêu khắc tinh xảo của người Chăm.', 'Ninh Thuận', 'Ninh Thuận', 'Ninh Thuận', 11.6012, 108.9606, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.LO2tIYILI_ngw7Kxfq0L7AHaE5&pid=Api&P=0&h=220"]', 4.5, 477, '07:00', '17:00', 0, '["tháp","tham quan","chụp ảnh","di tích"]');
INSERT INTO `destinations` VALUES (59, 'Vườn nho Ninh Thuận', 'Là các vườn nho nổi tiếng với nhiều sản phầm nho được sản xuất tại đây', 'Ninh Thuận', 'Ninh Thuận', 'Ninh Thuận', 11.534842, 108.981192, 'food', '["https://tse2.mm.bing.net/th?id=OIP.6FjDfpDUcJ0jZrJAVJKVGQHaEK&pid=Api&P=0&h=220"]', 4.2, 251, '06:00', '22:00', 0, '["tham quan","ăn uống","mua sắm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (60, 'Hồ Ba Bể', 'Là hồ nước mặn lớn ở Ninh Thuận, nơi sinh sống của nhiều loài thủy sản quý hiếm', 'Ninh Thuận', 'Ninh Thuận', 'Ninh Thuận', 22.4075, 105.6325, 'nature', '["https://tse2.mm.bing.net/th?id=OIP.tZEynIwFJnKOPgKiAntpigHaEK&pid=Api&P=0&h=220"]', 4.5, 831, '07:00', '17:00', 0, '["Hồ","chụp ảnh","tham quan","vui chơi"]');
INSERT INTO `destinations` VALUES (61, 'Đền Hùng', 'Là khu di tích lịch sử quốc gia đặc biệt, nơi thờ các vua Hùng – những người dựng nước đầu tiên của dân tộc Việt Nam.', 'Phú Thọ', 'Phú Thọ', 'Phú Thọ', 21.3731, 105.3064, 'religious', '["https://tse4.mm.bing.net/th?id=OIP.14_huh2INyBfjWTu11d8hAHaDX&pid=Api&P=0&h=220"]', 4.7, 839, '07:00', '18:00', 0, '["đền","tham quan","chụp ảnh","lịch sử"]');
INSERT INTO `destinations` VALUES (62, 'Làng cổ Hùng Lô', 'Nổi tiếng với các ngôi nhà cổ hàng trăm năm tuổi, cùng các nghề truyền thống như làm bánh chưng, bánh giầy.', 'Phú Thọ', 'Phú Thọ', 'Phú Thọ', 21.301547, 105.355793, 'historical', '["https://tse1.mm.bing.net/th?id=OIP.PuN6PGPDxH26j32lV3PDNwHaFj&pid=Api&P=0&h=220"]', 4.4, 2, '07:00', '17:00', 0, '["làng cổ","tham quan","lịch sử","chụp ảnh"]');
INSERT INTO `destinations` VALUES (63, 'Đảo Ngọc Xanh', 'Là khu du lịch sinh thái kết hợp nghỉ dưỡng, với cảnh quan thiên nhiên trong lành, công viên nước, trò chơi cảm giác mạnh và khu suối nước nóng', 'Phú Thọ', 'Phú Thọ', 'Phú Thọ', 21.336507, 105.408062, 'food', '["https://tse1.mm.bing.net/th?id=OIP.7efND2yzFvvpeKQnvS52ygHaEb&pid=Api&P=0&h=220"]', 4.7, 376, '06:00', '22:00', 0, '["tham quan","chụp ảnh","nghĩ dưỡng","vui chơi","ăn uống"]');
INSERT INTO `destinations` VALUES (64, 'Vườn quốc gia Xuân Sơn', 'Là một trong những khu bảo tồn thiên nhiên lớn nhất miền Bắc, nổi bật với hệ sinh thái rừng nhiệt đới và các loài động, thực vật phong phú', 'Phú Thọ', 'Phú Thọ', 'Phú Thọ', 21.302903, 105.409206, 'nature', '["https://tse2.mm.bing.net/th?id=OIP.P0f3XiQklTZTeh11_svtbwHaFt&pid=Api&P=0&h=220"]', 4.6, 444, '07:00', '17:00', 0, '["rừng","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (65, 'Suối nước nóng Thanh Thủy', 'Là khu vực có các dịch vụ nghỉ dưỡng và trị liệu hiện đại.', 'Phú Thọ', 'Phú Thọ', 'Phú Thọ', 21.335384, 105.378365, 'nature', '["https://tuongtaccongdong.s3.amazonaws.com/a4c1ca5a-cbd3-4f89-a276-0a70527ffa7a/79554a07-25ed-475e-b814-d62ae7bd06ea.jpg"]', 4.5, 352, '07:00', '17:00', 0, '["suối","chụp ảnh","vui chơi","nghĩ dưỡng"]');
INSERT INTO `destinations` VALUES (66, 'Gành Đá Đĩa', 'Một kỳ quan thiên nhiên độc đáo, Gành Đá Đĩa nổi bật với những cột đá bazan xếp chồng lên nhau như những chiếc đĩa.', 'Phú Yên', 'Phú Yên', 'Phú Yên', 13.3534, 109.2934, 'beach', '["https://tse4.mm.bing.net/th?id=OIP.wBFmyTIu6USelBkHI5SOBQHaE7&pid=Api&P=0&h=220"]', 4.7, 716, '00:00', '23:59', 0, '["biển","vui chơi","chụp ảnh","tham quan"]');
INSERT INTO `destinations` VALUES (67, 'Hòn Yến', 'Là một hòn đảo nhỏ với cảnh quan hoang sơ, nổi bật với những rạn san hô tuyệt đẹp.', 'Phú Yên', 'Phú Yên', 'Phú Yên', 13.055505, 109.071639, 'beach', '["https://tse2.mm.bing.net/th?id=OIP.5r-1v-qQkq4A7RZF8ZALHgHaE7&pid=Api&P=0&h=220"]', 3.8, 1, '00:00', '23:59', 0, '["tham quan","chụp ảnh","vui chơi"]');
INSERT INTO `destinations` VALUES (68, 'Hải đăng Đại Lãnh', 'Là điểm cực Đông của Việt Nam, nơi đón ánh bình minh đầu tiên trên đất liền', 'Phú Yên', 'Phú Yên', 'Phú Yên', 12.8885, 109.4552, 'beach', '["https://tse1.mm.bing.net/th?id=OIP.Q7kI4toZEEYCxS-pM3yRfgHaDX&pid=Api&P=0&h=220"]', 4.5, 623, '00:00', '23:59', 0, '["biển","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (69, 'Suối nước nóng Triêm Đức', 'Là một điểm đến thú vị để thư giãn và ngâm mình trong làn nước khoáng ấm áp.', 'Phú Yên', 'Phú Yên', 'Phú Yên', 13.056765, 109.13306, 'nature', '["https://tripmap.vn/wp-content/uploads/2021/07/suoi-nuoc-khoang-triem-duc-1626245826513.jpg"]', 4.6, 130, '07:00', '17:00', 0, '["suối","tham quan","nghĩ dưỡng","chụp ảnh"]');
INSERT INTO `destinations` VALUES (70, 'Tháp Nhạn', 'Tháp Nhạn nằm trên núi Nhạn ở thành phố Tuy Hòa, là một công trình kiến trúc Chăm cổ kính và linh thiêng.', 'Phú Yên', 'Phú Yên', 'Phú Yên', 13.0952, 109.3125, 'historical', '["https://tse3.mm.bing.net/th?id=OIP.j7Y3zi_M9U91OkWt3Da8zQHaJQ&pid=Api&P=0&h=220"]', 4.4, 152, '07:00', '17:00', 0, '["tháp","tham quan","chụp ảnh","di tích"]');
INSERT INTO `destinations` VALUES (71, 'Động Phong Nha', 'Phong Nha - Kẻ Bàng, được UNESCO công nhận là Di sản Thiên nhiên Thế giới.', 'Quảng Bình', 'Quảng Bình', 'Quảng Bình', 17.5903, 106.2836, 'checkin', '["https://tse4.mm.bing.net/th?id=OIP.JdKfzuou2kznDok9wau7EQHaD8&pid=Api&P=0&h=220"]', 4.8, 623, '00:00', '23:59', 0, '["động","tham quan","thám hiểm","chụp ảnh"]');
INSERT INTO `destinations` VALUES (72, 'Bãi Đá Nhảy', 'Là nơi nổi bật với những khối đá có hình thù độc đáo bên bờ biển.', 'Quảng Bình', 'Quảng Bình', 'Quảng Bình', 17.7925, 106.5053, 'beach', '["https://cdn3.ivivu.com/2023/04/bai-da-nhay-ivivu-1.jpg"]', 4.4, 609, '00:00', '23:59', 0, '["biển","tham quan","chụp ảnh"]');
INSERT INTO `destinations` VALUES (73, 'Đền Thánh Mẫu Liễu Hạnh', 'Là nơi linh thiêng thờ vị thánh trong tín ngưỡng dân gian Việt Nam.', 'Quảng Bình', 'Quảng Bình', 'Quảng Bình', 17.493456, 106.600255, 'religious', '["https://tse2.mm.bing.net/th?id=OIP.lCVtkvtMPFPPCOoehvKPqgHaFj&pid=Api&P=0&h=220"]', 4.3, 536, '07:00', '18:00', 0, '["đền","tham quan","chụp ảnh","lịch sử"]');
INSERT INTO `destinations` VALUES (74, 'Nhà lưu niệm Đại tướng Võ Nguyên Giáp', 'Là nơi lưu giữ những kỷ vật gắn bó với tuổi thơ của Đại tướng Võ Nguyên Giáp.', 'Quảng Bình', 'Quảng Bình', 'Quảng Bình', 17.4651, 106.661114, 'historical', '["https://tse4.mm.bing.net/th?id=OIP.PCk93VVT5QVj78DW3MA54AHaE8&pid=Api&P=0&h=220"]', 4.5, 129, '07:00', '17:00', 0, '["lịch sử","tham quan","di tích","văn hóa"]');
INSERT INTO `destinations` VALUES (75, 'Sông Chày ', 'Là điểm đến lý tưởng cho những người yêu thích phiêu lưu, Sông Chày kết hợp giữa vẻ đẹp sông nước và hang động.', 'Quảng Bình', 'Quảng Bình', 'Quảng Bình', 17.5865, 106.267, 'nature', '["https://tse1.mm.bing.net/th?id=OIP.5-sP9bg-nnIa5GiTqFgWXQHaEK&pid=Api&P=0&h=220"]', 4.4, 504, '07:00', '17:00', 0, '["tham quan","chụp ảnh","khám phá"]');
INSERT INTO `destinations` VALUES (76, 'Phố cổ Hội An', 'Những ngôi nhà cổ kính và có kiến trúc độc đáo như: những ngôi nhà lợp ngối đá, nhưng bức tường vàng mang lại vẻ đẹp
INSERT INTO `destinations` VALUES (77, 'Bãi biển An Bàng', 'Sở hữu vẻ đẹp yên bình, hoang sơ với những bãi các vàng, biển xanh, khí hậu vô cùng mát mẻ và trong lành.', 'Quảng Nam', 'Quảng Nam', 'Quảng Nam', 15.914, 108.3378, 'beach', '["http://surl.li/hdwlva"]', 4, 603, '00:00', '23:59', 0, '["biển","cát vàng","mát mẻ","yên bình","hoang sơ"]');
INSERT INTO `destinations` VALUES (78, 'Tháp Chiên Đàn', 'Hiểu hơn về văn hóa Champa, sở hữu một nhà trưng bày nhưng tác phẩm điêu khắc tiêu biểu, vô vàn những món đồ quý hiếm', 'Quảng Nam', 'Quảng Nam', 'Quảng Nam', 15.579256, 108.453776, 'culture', '["http://surl.li/sdynak"]', 3.8, 2, '07:00', '17:00', 0, '["Champa","điêu khắc","quý hiếm"]');
INSERT INTO `destinations` VALUES (79, 'Đỉnh Quế', 'Với độ cao 1400km, được coi là ngọn núi đẹp nhất của Trường Sơn hùng vĩ, bạn có thể đắm chìm vào không gian cảnh sắt
INSERT INTO `destinations` VALUES (80, 'Thánh Địa Mỹ Sơn', 'Một thung lũng có đường kính 2km, Nơi đây bao quanh là núi đồi, vô cùng ẩn mình. Địa điểm này từng là nơi tổ chức cúng tế 
INSERT INTO `destinations` VALUES (81, 'Núi Thiên Ấn', 'Là một ngọn núi từ lâu đã rất nổi tiếng với khung cảnh hùng vĩ và mang lại một giá trị lịch sử vô cùng lớn lao, với vẻ đẹp thơ
INSERT INTO `destinations` VALUES (82, 'Bãi biển Mỹ Khê', 'Một trong những bãi biển quyến rũ nhất hành tinh, nơi đây có nhiều khách sạn view biển đẹp mắt phù hợp để tận hưởng kì nghỉ', 'Quảng Ngãi', 'Quảng Ngãi', 'Quảng Ngãi', 15.1642, 108.9266, 'beach', '["http://surl.li/exhizd"]', 4.5, 765, '00:00', '23:59', 0, '["biển","quyến rũ","kì nghỉ","khách sạn","trắng phao"]');
INSERT INTO `destinations` VALUES (83, 'Đồng muối Sa Huỳnh', 'Vựa muối quan trọng nhất miền Trung thân yêu của chúng ta, những bãi muối trắng phao, đến nơi đây bạn sẽ được trãi nghiệm các hoạt động hằng ngày
INSERT INTO `destinations` VALUES (84, 'Thác Trắng', 'Khùng cảnh ở đây ấn tượng với rừng núi hoang sơ, trong lành, dòng thác đổ xuống giữa khung cảnh bao quanh là biết bao cây cối sông suối tung bọt trắng xóa', 'Quảng Ngãi', 'Quảng Ngãi', 'Quảng Ngãi', 15.133402, 108.799952, 'nature', '["http://surl.li/vifezm"]', 4, 232, '07:00', '17:00', 0, '["rừng núi","hoang sơ","thác","cây cối","sông"]');
INSERT INTO `destinations` VALUES (85, 'Đèo Vi O Lắc', 'Nằm cao hơn 1300m so với mực nước biển, sự quanh co uốn lượn của các cung đường cùng với không khí thơ mộng luôn mang đến nhưng vẻ đẹp tuyệt mỹ cùng hàng cỏ xanh tươi mọc hai bên đường khi du khách đi lên đèo là nhưng nét ấn tượng nhất, thú vị nhất', 'Quảng Ngãi', 'Quảng Ngãi', 'Quảng Ngãi', 15.099945, 108.796602, 'beach', '["http://surl.li/izldds"]', 4, 157, '00:00', '23:59', 0, '["đèo","thơ mộng","quanh co","uốn lượn","cung đường","1300m"]');
INSERT INTO `destinations` VALUES (86, 'Vịnh Hạ Long', 'Là một trong những di sản thiên nhiên thế giới được UNESCO công nhận. Với diện tích 1553km2, gần 2000 hòn đảo lớn nhỏ, 
INSERT INTO `destinations` VALUES (87, 'Biển Bãi Cháy', 'Bãi Cháy luôn thu hút rất nhiều du khách đến tham quan trải nghiệm và tắm biển. Bãi biển cùng đã có thêm những hoạt động thể thao trên biển như cano, dù bay hay nhà phao để du khách có thể tận hưởng những dịch vụ cao cấp hơn. ', 'Quảng Ninh', 'Quảng Ninh', 'Quảng Ninh', 20.96, 107.048, 'beach', '["http://surl.li/saniob"]', 3.9, 184, '00:00', '23:59', 0, '["Bãi biển","tắm biển","dù bay","nhà phao"]');
INSERT INTO `destinations` VALUES (88, 'Công viên Hạ Long', 'Du lịch Hạ Long thì chắc chắn không nên bỏ qua Sun World Halong Park - khu phức hợp giải trí nổi tiếng dành cho mọi lứa tuổi. Nếu bạn đã từng đến VinWonders thì công viên Hạ Long cũng là một thiên đường tương tự như vậy, nhưng sẽ náo nhiệt hơn nhiều nhé. ', 'Quảng Ninh', 'Quảng Ninh', 'Quảng Ninh', 20.9572, 107.044, 'theme_park', '["http://surl.li/kdadyl"]', 4.4, 993, '09:00', '18:00', 350000, '["công viên","náo nhiệt","giải trí"]');
INSERT INTO `destinations` VALUES (89, 'Làng chài Cửa Vạn', 'Không chỉ được tận hưởng không gian yên tĩnh, thanh bình nơi đây, du khách còn có thêm những hiểu biết về đời sống văn hóa, thường nhật của các ngư dân. Ngư dân ở đây hết sức thân thiện và mến khách. Hành khách có thể chèo thuyền thúng, cắt cá, câu mực… để hiểu hơn cuộc sống dân chài.', 'Quảng Ninh', 'Quảng Ninh', 'Quảng Ninh', 20.855, 107.113, 'culture', '["http://surl.li/mxcags"]', 4.6, 741, '07:00', '17:00', 0, '["yên tĩnh","thanh bình","đời sống","văn hóa","ngư dân","thân thiện","mến khách","chèo thuyền","cắt cá","câu mực"]');
INSERT INTO `destinations` VALUES (90, 'Động Thiên Cung', 'Với cấu trúc nhiều tầng, nhiều lớp phức tạp, các khối nhũ đá ở đây có nhiều hình dáng kỳ lạ. Hang động này đã được đầu tư
INSERT INTO `destinations` VALUES (91, 'Nghĩa trang Liệt sĩ Quốc gia Trường Sơn', 'Địa điểm ghi dấu ấn về những mất mát, minh chứng cho những gì tàn bạo nhất của giặc ngoại xâm. Nơi này đã đi vào lịch sử, biểu tượng của sự bi tráng và lòng anh dũng của những con người yêu nước, đặt sự độc lập và vận mệnh dân tộc lên hàng đầu.', 'Quảng Trị', 'Quảng Trị', 'Quảng Trị', 16.819645, 107.085324, 'historical', '["http://surl.li/mebyuu"]', 4.8, 631, '07:00', '17:00', 0, '["ghi dấu","mất mác","minh chứng","tàn bạo","lịch sử","anh dũng","yêu nước","độc lập","vận mệnh."]');
INSERT INTO `destinations` VALUES (92, 'Địa đạo Vịnh Mốc', 'Công trình này ở sâu lòng đất, được người dân đào trong kháng chiến chống Mỹ. Địa đạo gồm có nhiều khu vực như trường học, kho hậu cần, bệnh viện, khu quân sự và khu gia đình. ', 'Quảng Trị', 'Quảng Trị', 'Quảng Trị', 17.0839, 107.1079, 'beach', '["http://surl.li/ogxfcj"]', 4.6, 912, '00:00', '23:59', 0, '["sâu","lòng đất","kháng chiến"]');
INSERT INTO `destinations` VALUES (93, 'Bãi biển Cửa Tùng', ' Mùa hè đến bãi biển này, bạn sẽ thấy được nét đẹp bình yên của biển xanh, cát trắng. Khung cảnh tĩnh lặng vào buổi chiều hoàng hôn khiến bao trái tim bị mê hoặc.', 'Quảng Trị', 'Quảng Trị', 'Quảng Trị', 17, 107.098, 'beach', '["http://surl.li/bxuyel"]', 4.3, 651, '00:00', '23:59', 0, '["Bãi biển","biển xanh","cát trắng","tĩnh lặng"]');
INSERT INTO `destinations` VALUES (94, 'Đồi hoa Miền Viên Thảo', 'Nổi bật với cánh đồng hoa rực rỡ và nở rộ quanh năm. Thời tiết ở đây cực kỳ mát mẻ nên việc trồng hoa khá thuận lợi. Địa điểm du lịch Quảng Trị có đủ hoa hồng, cúc họa mi, hoa cải vàng. Đặc biệt, nếu bạn yêu thích hoa tam giác mạch thì không thể bỏ hoa Miền Viên Thảo. ', 'Quảng Trị', 'Quảng Trị', 'Quảng Trị', 16.846078, 107.081728, 'nature', '["http://surl.li/cidfnv"]', 4.3, 785, '07:00', '17:00', 0, '["Cánh đồng hoa","thích hoa","mát mẻ"]');
INSERT INTO `destinations` VALUES (95, 'Đỉnh Cu Vơ', 'Rất thích hợp cho nhóm bạn đi phượt. Cực kì thu hút các bạn trẻ đến để săn mây. Vào buổi sáng sớm, đứng ở ngọn núi, mở ra trước mắt bạn là những tầng mây trắng. Khoảnh khắc ánh nắng mặt trời rọi xuống thực sự đẹp biết bao.', 'Quảng Trị', 'Quảng Trị', 'Quảng Trị', 16.809855, 107.13826, 'nature', '["http://surl.li/yoyuch"]', 4.7, 279, '07:00', '17:00', 0, '["Đồi","săn mây","phượt","núi","mây trắng"]');
INSERT INTO `destinations` VALUES (96, 'Chợ nổi Ngã Năm', 'bày bán đủ các loại mặt hàng từ thực phẩm cho đến nhu yếu phầm. Đặc biệt hơn hết, không thể không nhắc đến các ghe/ xuồng đầy ắp các loại trái cây nhiệt 
INSERT INTO `destinations` VALUES (97, 'Chùa Dơi', 'Kiến trúc của ngôi chùa này được xem là tiêu biểu của Phật giáo Nam tông Khmer, chùa được xây dựng vào thế kỷ 16 nhưng cho đến nay toàn bộ công trình còn giữ được tình trạng tốt và vẫn là nơi sinh hoạt tôn giáo mang ý nghĩa quan trọng của người dân trong vùng. Điều Đặc biệt khi đi đây là du khách sẽ thấy hàng nghìn con dơi khá lớn treo mình trên cây trong khuôn viên chùa giống như chúng đã quen thuộc với nơi này vậy', 'Sóc Trăng', 'Sóc Trăng', 'Sóc Trăng', 9.5866, 105.9827, 'religious', '["http://surl.li/tkcaxe"]', 4.5, 840, '07:00', '18:00', 0, '["chùa","Phật giáo","con dơi"]');
INSERT INTO `destinations` VALUES (98, 'Vườn cò Tân Long', 'Với quang cảnh thiên nhiên hoang sơ và hệ sinh thái động thực vật đa dạng. Đặc biệt là các giống loài cò quý hiếm.', 'Sóc Trăng', 'Sóc Trăng', 'Sóc Trăng', 9.58882, 105.980053, 'attraction', '["http://surl.li/acmlvm"]', 4.2, 914, '07:00', '17:30', 0, '["hoang sơ","cò","quý hiếm"]');
INSERT INTO `destinations` VALUES (99, 'Biển Hồ Bể', 'Khu vực này được hình thành do sự bãi bồi và quá trình xâm lấn của nước biển, làm nên một vùng hồ trũng rộng lớn. Bãi biển
INSERT INTO `destinations` VALUES (100, 'Chùa Som Rong', 'Là một nơi đặc biệt quan trọng không chỉ do tín ngưỡng tôn giáo, mà còn do ngôi chùa này có một thư viện lớn với hơn 1500 đầu sách, phục vụ cho các bạn thiếu nhi, bà con tại nơi này. Ngôi bảo tháp được phủ một màu xám huyền bí thay vì màu vàng thường gặp; Pho tượng phật nằm dài hơn 63 mét, cao hơn mặt đất khoảng 28 mét, cộng thêm chiều cao 22 mét khiến cho pho tượng vô cùng uy nghi; chùa Som Rong thường được nhiều khách du lịch lựa chọn ghé thăm', 'Sóc Trăng', 'Sóc Trăng', 'Sóc Trăng', 9.611379, 105.999398, 'religious', '["http://surl.li/btdhtl"]', 4.8, 1, '07:00', '18:00', 0, '["tín ngưỡng","tôn giáo","bảo tháp","tượng"]');
INSERT INTO `destinations` VALUES (101, 'Mộc Châu', 'với đặc sản là những mùa hoa ban, hoa anh đào, hoa mận, hoa cải vàng… tràn ngập hương sắc. Mộc Châu cũng là cái tên kinh điển nhất khi nhắc đến du lịch vùng Tây Bắc với cung đường phượt đẹp như tranh vẽ', 'Sơn La', 'Sơn La', 'Sơn La', 20.8295, 104.684, 'food', '["http://surl.li/dzxuss"]', 4.5, 762, '06:00', '22:00', 0, '["hoa đào","hoa mận","đường phượt"]');
INSERT INTO `destinations` VALUES (102, 'Ngũ động bản Ông', 'Đây là hệ thống gồm 5 hang động được người dân địa phương phát hiện lần đầu tiên vào năm 2006. Vì tại đây chưa có nhiều dịch vụ du lịch nên những hang động vẫn giữ được vẻ đẹp hoang sơ, huyền bí. Bên trong hang được điểm xuyến bởi những khối đá nhũ thạch khổng lồ với hình thù độc đáo.', 'Sơn La', 'Sơn La', 'Sơn La', 21.364811, 103.904544, 'nature', '["http://surl.li/pdnwji"]', 4.5, 135, '07:00', '17:00', 0, '["động","hoang sơ","huyền bí","đá nhũ hạch"]');
INSERT INTO `destinations` VALUES (103, 'Rừng thông bản Áng ', 'Khu rừng có tổng diện tích lên đến 43ha với bầu không khí trong lành và khung cảnh thông xanh trập trùng trông rất mát mắt. 
INSERT INTO `destinations` VALUES (104, 'Thác Dải Yếm', 'Thác cao hơn 100m, chia thành 2 tầng chính. Trong đó tầng thứ nhất có tổng cộng 9 bậc, tầng thứ hai có 5 bậc. Vào độ từ tháng 4 đến tháng 10 hàng năm, khi lượng nước đổ về nhiều sẽ tạo nên những dòng chạy mạnh mẽ, tung bọt trắng xóa rất đẹp mắt', 'Sơn La', 'Sơn La', 'Sơn La', 20.8192, 104.7307, 'nature', '["http://surl.li/uvrsec"]', 4.6, 221, '07:00', '17:00', 0, '["dòng chảy","thác"]');
INSERT INTO `destinations` VALUES (105, 'Đỉnh Tà Xua', 'Từ trên đỉnh, bạn có thể phóng tầm mắt chiêm ngưỡng khung cảnh hùng vĩ xung quanh với những dải ruộng bậc thang xanh mướt, thấp thoáng xa xa là mái lá khói bếp, tay có thể chạm đến mây trời.', 'Sơn La', 'Sơn La', 'Sơn La', 21.284, 104.414, 'nature', '["http://surl.li/hpreeq"]', 4.8, 350, '07:00', '17:00', 0, '["đỉnh","ruộng bậc thang","mây trời."]');
INSERT INTO `destinations` VALUES (106, 'Núi Bà Đen', 'núi Bà Đen còn được biết đến như “nóc nhà” của Nam Bộ với đỉnh cao nhất là 986 m, diện tích 24 km², Nếu yêu thích vẻ đẹp bao la của đất trời, muốn chiêm ngưỡng cảnh đẹp từ trên cao thì có thể lựa chọn di chuyển bằng cáp treo từ chân núi lên đỉnh núi.', 'Tây Ninh', 'Tây Ninh', 'Tây Ninh', 11.3715, 106.1661, 'nature', '["http://surl.li/zaoqyj"]', 4.5, 743, '07:00', '17:00', 0, '["nóc nhà","cáp treo","núi"]');
INSERT INTO `destinations` VALUES (107, 'Tòa thánh Tây Ninh', 'Tòa thánh chính là địa điểm du lịch Tây Ninh dành cho những dân phượt muốn tìm hiểu về nét văn hóa và nét kiến trúc tiêu biểu tại nơi đây, Phong cách thiết kế của công trình vô cùng độc đáo, các chi tiết được trạm trổ hoa văn kỳ công và mang nhiều nét biểu tượng cho văn hóa mảnh đất này.', 'Tây Ninh', 'Tây Ninh', 'Tây Ninh', 11.3105, 106.1317, 'culture', '["http://surl.li/wqpvnz"]', 4.7, 864, '07:00', '17:00', 0, '["tòa thánh","kiến trúc","trạm trổ","hoa văn"]');
INSERT INTO `destinations` VALUES (108, 'Hồ Dầu Tiếng', 'Hồ Dầu Tiếng được xây dựng với mục đích cung cấp nước cho sinh hoạt, ngoài ra nơi đây còn là điểm du lịch vô cùng hot với phong cảnh êm đềm, thơ mộng tựa như trong chuyện cổ tích. Bạn sẽ được thả hồn vào khung cảnh thiên nhiên tuyệt đẹp với non nước hữu tình, mây trời hiền hòa, sắc xanh bạt ngàn của màu nước và màu trời. Những ghềnh đá nhấp nhô quanh ốc đảo trên hồ chính là điểm dừng chân và cũng là background tuyệt đẹp cho bạn để sống ảo.', 'Tây Ninh', 'Tây Ninh', 'Tây Ninh', 11.2966, 106.356, 'beach', '["http://surl.li/lftayu"]', 4, 541, '00:00', '23:59', 0, '["thiên nhiên","cung cấp nước","ghềnh đá","ốc đảo"]');
INSERT INTO `destinations` VALUES (109, 'Tháp Chóp Mạt ', 'Tòa tháp này có kiến trúc rất đặc biệt đó chính là được xây dựng nhỏ dần lên phía trên nhưng lại không hề có đỉnh chóp. Người Óc Eo rất khéo léo và thông minh khi xây dựng công trình, họ không hề chút xi măng nào làm vật liệu kết dính. Khi đến đây tham quan, du khách có thể thoải mái check in tại một không gian vô cùng yên bình và mang nét hoài cổ của địa điểm du lịch Tây Ninh này. ', 'Tây Ninh', 'Tây Ninh', 'Tây Ninh', 11.309293, 106.080749, 'culture', '["http://surl.li/wnvrio"]', 3.8, 1, '07:00', '17:00', 0, '["tháp","nhỏ dần","hoài cổ"]');
INSERT INTO `destinations` VALUES (110, 'Vườn quốc gia Lò Gò -  Xa Mát', 'tới đây, du khách có thể ngắm nhìn các loài động, thực vật quý hiếm mà bạn khó có cơ hội được nhìn ngắm ngoài đời. Có rất nhiều những loài động vật quý hiếm được liệt kê vào sách đỏ. Ngoài ra, du khách cũng có thể trải nghiệm rất nhiều những hoạt động như đạp xe xuyên rừng, khám phá rừng bằng đường sông,…', 'Tây Ninh', 'Tây Ninh', 'Tây Ninh', 11.6145, 106.1485, 'nature', '["http://surl.li/mobftk"]', 4, 455, '07:00', '17:00', 0, '["dđộng vật","thực vật","quý hiếm","xuyên rừng"]');
INSERT INTO `destinations` VALUES (111, 'Chùa Keo', 'Chùa Keo ở Thái Bình được xếp hạng là ngôi chùa cổ đẹp nhất tại Việt Nam. Chùa được xây dựng theo kiến trúc cổ kín từ thời nhà Lê. Chính vì lẽ đó mà chùa Keo được xem là một trong những địa điểm check-in Thái Bình mà bạn nhất định phải đến tham quan.', 'Thái Bình', 'Thái Bình', 'Thái Bình', 20.4368, 106.302, 'religious', '["http://surl.li/ivqjww"]', 4.5, 398, '07:00', '18:00', 0, '["chùa","cổ kín"]');
INSERT INTO `destinations` VALUES (112, 'Bãi biển Đồng Châu', 'Còn giữ nguyên vẻ đẹp hoang sơ thì hãy đến với bãi biển Đồng Châu. Với bờ cát trải dài 5km ôm lấy mặt biển mênh mông, xanh mướt đã vẻ nên một địa điểm du lịch độc đáo tại Bắc Trung Bộ. hững chiếc chòi canh nhấp nhô trên mặt nước tạo nên cảnh sắt thật là hữu tình.', 'Thái Bình', 'Thái Bình', 'Thái Bình', 20.449135, 106.32187, 'beach', '["http://surl.li/sbizem"]', 3.5, 452, '00:00', '23:59', 0, '["hoang sơ","cò","quý hiếm"]');
INSERT INTO `destinations` VALUES (113, 'Bãi biển Cồn Đen', 'hình ảnh đẹp nhất của biển và sự hoang sơ của khu rừng nguyên sinh. Đặc biệt, vào thời điểm bình minh và hoàng hôn thì vẻ đẹp nơi đây lại trở nên quyến rũ đến kỳ lạ, lúc này cũng là khoảnh khắc được nhiều người săn đón nhất. Với vẻ đẹp trong lành từ không khí cho đến mặt nước biển trong xanh cùng bãi cát trắng thì đây đích thị là một background cực xịn', 'Thái Bình', 'Thái Bình', 'Thái Bình', 20.457302, 106.354487, 'beach', '["http://surl.li/yjhohk"]', 4, 683, '00:00', '23:59', 0, '["biển","hoang sơ","cát trắng","quyến rũ"]');
INSERT INTO `destinations` VALUES (114, 'Nhà thờ Bác Trạch', 'Đây chính là một trong những nhà thờ lớn nhất Việt Nam hiện nay với hoa văn trang trí công phu theo lối kiến trúc Roman. 
INSERT INTO `destinations` VALUES (115, 'Làng dệt chiếu Hới', 'Nổi tiếng với những làng nghề truyền thống gần hàng trăm năm tuổi.  bạn còn được hiểu thêm về cuộc sống giản dị của người dân trong làng. Và bạn sẽ được người dân giới thiệu về quy trình để tạo ra được một một chiếc chiếu truyền thống, từ thu hoạch chế biến cói cho tới khâu thành phẩm. Những trải nghiệm này sẽ là một kỷ niệm khó quên cho chuyến đi của bạn.', 'Thái Bình', 'Thái Bình', 'Thái Bình', 20.475812, 106.321834, 'culture', '["http://surl.li/hglflh"]', 3.4, 1, '07:00', '17:00', 0, '["truyền thống","chiếu."]');
INSERT INTO `destinations` VALUES (116, 'Hồ Núi Cốc', 'Du khách có thể trải nghiệm ngồi thuyền thúng, khám phá động Thế giới Cổ tích và Âm phủ, động Ba Cây Thông, tham quan quần thể Thuyết Nhân Quả - Chùa Thiêng Thác Vàng, ngôi chùa nằm trong lòng Phật lớn nhất miền Bắc được ghi nhận kỷ lục Guniess.', 'Thái Nguyên', 'Thái Nguyên', 'Thái Nguyên', 21.5787, 105.7, 'religious', '["http://surl.li/uizspq"]', 4.5, 797, '07:00', '18:00', 0, '["thuyền thúng","Guniess","chùa","tham quan"]');
INSERT INTO `destinations` VALUES (117, 'Đồi chè Tân Cương', 'Một trong những địa điểm du lịch Thái Nguyên nổi tiếng chắc chắn không thể quên kể đến đó chính là đồi chè Tân Cương. Đây là một địa điểm thu hút sự quan tâm từ đông đảo khách du lịch nhờ vào cảnh quan thiên nhiên tuyệt đẹp, được bao phủ bởi một sắc xanh mát lạnh. Bất cứ ai đến đồi chè Tân Cương du lịch cũng đều có thể cảm nhận được sự tươi mới từ sâu trong tâm hồn, giúp bạn cảm thấy dễ chịu hơn bao giờ hết.', 'Thái Nguyên', 'Thái Nguyên', 'Thái Nguyên', 21.554, 105.73, 'beach', '["http://surl.li/hdpzzj"]', 4.5, 682, '00:00', '23:59', 0, '["trè","xanh","mát lạnh","dễ chịu"]');
INSERT INTO `destinations` VALUES (118, 'Hồ Mai Miếu', 'nơi đây vốn được ví như một bức tranh thủy mặc vô cùng ấn tượng với khung cảnh núi non hữu tình khiến lòng người say đắm. Hồ Văn Miếu nổi bật với mặt hồ rộng, nước hồ trong veo kết hợp với cảnh quan kì vĩ xung quanh đã tạo nên một khung cảnh thơ mộng hấp dẫn hơn bao giờ hết. Cũng chỉ vì chưa được tập trung khai thác du lịch mạnh mẽ mà hồ Vai Miếu đã giữ được vẹn nguyên nét đẹp hoang sơ và trữ tình khiến nhiều người say mê.', 'Thái Nguyên', 'Thái Nguyên', 'Thái Nguyên', 21.61306, 105.847512, 'religious', '["http://surl.li/jnxjfw"]', 3.5, 79, '07:00', '18:00', 0, '["tranh","núi","ấn tượng"]');
INSERT INTO `destinations` VALUES (119, 'Động Linh Sơn', 'Động Linh Sơn tỉnh Thái Nguyên có diện tích rộng rãi, vào mùa hè rất mát mẻ và mùa đông sẽ ấm áp vô cùng. Động nằm tại khu vực lưng chừng núi đá rộng lớn nên đã được người dân nơi đây lựa chọn xây dựng chùa thờ Phật. Cứ vào các ngày rằm, mùng một, người dân từ Thái Nguyên và nhiều tỉnh thành lân cận khác đều sẽ đến đây dâng hương lễ Phật rất náo nhiệt.', 'Thái Nguyên', 'Thái Nguyên', 'Thái Nguyên', 21.552821, 105.829472, 'religious', '["http://surl.li/xogioj"]', 4, 765, '07:00', '18:00', 0, '["động","núi đã"]');
INSERT INTO `destinations` VALUES (120, 'Thác Đát Đắng', 'bạn sẽ có cảm giác hệt như đang lạc bước vào một không gian mới mẻ, được tránh xa hoàn toàn sự xô bồ và náo nhiệt nơi phố thị. Cảnh núi rừng hùng vĩ, dòng nước xanh trong mát lành chính là những thứ ấn tượng khiến bạn có cảm giác thật sự thư giãn và mong muốn được tận hưởng sự yên bình hiếm thấy này mãi không thôi.', 'Thái Nguyên', 'Thái Nguyên', 'Thái Nguyên', 21.578003, 105.807192, 'nature', '["http://surl.li/mxojry"]', 4, 987, '07:00', '17:00', 0, '["núi rừng","bình yên","thác"]');
INSERT INTO `destinations` VALUES (121, 'Suối Hiêu', 'Nằm giữa khu rừng xanh mướt và những cánh đồng lúa bình yên, suối Hiêu cứ như thế mà yên ả chảy ríu rít ngày ngày để mang đến một địa điểm check-in Thanh Hóa vô cùng thơ mộng. Như một đóa hồng có gai, suối mang vẻ đẹp quyến rũ đến nao lòng nhưng lại có khả năng hóa đá tạm thời những gì rơi xuống bởi hàm lượng vôi rất cao.', 'Thanh Hóa', 'Thanh Hóa', 'Thanh Hóa', 19.812098, 105.811655, 'nature', '["http://surl.li/fpkeqm"]', 4, 658, '07:00', '17:00', 0, '["ríu rít","thơ mộng","quyến rũ","đồng lúa"]');
INSERT INTO `destinations` VALUES (122, 'Ruộng bậc thang Pù Luông', 'Đến Thanh Hóa mà không đặt chân đến các đến các ruộng bậc thang Pù Luông để check-in thì thật là một thiếu sót to lớn. Ruộng bậc thang Pù Luông vừa là niềm tự hào của nhân dân ta, vừa là địa điểm check-in Thanh Hóa siêu hot', 'Thanh Hóa', 'Thanh Hóa', 'Thanh Hóa', 20.4745, 105.205, 'nature', '["http://surl.li/zkyyiq"]', 4.7, 801, '07:00', '17:00', 0, '["ruộng bậc thang"]');
INSERT INTO `destinations` VALUES (123, 'Suối cá Thần Cẩm Thủy', 'Suối cá Thần là địa điểm gắn liền với tín ngưỡng của người dân tộc Mường, bởi nơi đây có lượng sinh sống đặc biệt dày đặc. Hiện nay, suối cá cũng đã trở thành một trong những địa điểm check-in Thanh Hóa độc đáo và nổi tiếng mà bạn có thể thêm vào lịch trình của mình nhé.', 'Thanh Hóa', 'Thanh Hóa', 'Thanh Hóa', 19.845448, 105.780774, 'nature', '["http://surl.li/bvriuv"]', 4.5, 499, '07:00', '17:00', 0, '["tín ngưỡng","Mường","suối"]');
INSERT INTO `destinations` VALUES (124, 'Vường quốc gia Bến En', 'là nơi sinh sống của nhiều loài động thực vật quý hiếm có thể kể đến lim xanh, bù hương, chò chỉ… gấu ngựa, phượng hoàng đất…Vườn Quốc gia Bến En được ví như lá phổi xanh xanh của Thanh Hóa bởi những cánh rừng xanh bất tận. Và xen lẫn vào màu xanh ấy là những hang động, dải núi đá cao gập ghềnh đã tạo nên những địa điểm check-in Thanh Hóa độc đáo và đĩnh đạc nhất.', 'Thanh Hóa', 'Thanh Hóa', 'Thanh Hóa', 19.548, 105.558, 'nature', '["http://surl.li/jewolc"]', 3.3, 2, '07:00', '17:00', 0, '["lá phổi xanh","bất tấn","hang động","núi đá"]');
INSERT INTO `destinations` VALUES (125, 'Động Từ Thức', 'Đào và được tạo thành từ muôn vàn hình dạng nhũ đá. Sâu bên trong động còn có một hồ nước nhỏ tạo nên một bức tranh vô cùng thơ mộng.', 'Thanh Hóa', 'Thanh Hóa', 'Thanh Hóa', 19.805365, 105.734217, 'nature', '["http://surl.li/wbpxdd"]', 4, 758, '07:00', '17:00', 0, '["nhũ đá","hồ nước","thơ mộng"]');
INSERT INTO `destinations` VALUES (126, 'Đại Nội Huế', 'Nằm ở bờ Bắc của dòng sông Hương thơ mộng trữ tình, Đại Nội Huế với kiến trúc nghệ thuật cung đình và vườn hào độc đáo. Cũng là trung tâm hành chính, chính trị của triều đình nhà Nguyễn và nơi sinh hoạt của nhà vua hoàng gia ngày xưa.', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 16.4755, 107.57141, 'attraction', '["http://surl.li/hwchra"]', 4.9, 688, '06:30 summer; 07:00 ', '18:00 summer; 17:30 ', 200000, '["kiến trúc","nghệ thuật","hành chính","chính trị","vua"]');
INSERT INTO `destinations` VALUES (127, 'Chùa Thiên Mụ', 'Ngôi chùa này là điểm tham quan Huế nổi tiếng và không thể thiếu trong mọi hành trình đến khám phá Huế của du khách.Cách trung tâm thành phố Huế khoảng 5km về phía Tây, với một tên gọi khác là chùa Linh Mụ, chùa nằm trên đồi Hà Khê, nhìn xuống dòng Hương thơ mộng. Ngôi chùa mang vẻ đẹp cổ kính lâu đời với những khuông viên rộng rãi,khung cảnh thanh tịnh và đặc biệt hình tháp Phước Duyên 7 tầng tại sân trước của chùa được xem là biểu tượng đặc trưng cho thành phố Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 16.4536, 107.5448, 'religious', '["http://surl.li/erxdid"]', 4.5, 123, '07:00 (tham khảo)', '17:00 (tham khảo)', 0, '["chùa","cổ kính","Linh Mụ","lâu đời","đặc trưng"]');
INSERT INTO `destinations` VALUES (128, 'Lăng Khải Định', 'Nhắc đến Huế người ta không khỏi đề cập đến lăng tẩm thời Nguyễn. Tour du lịch của bạn sẽ thú vị hơn, nếu đừng chân ghé thăm điểm đến Lăng Khải Định. Du khách sẽ được chiêm ngưỡng đỉnh cao nghệ thuật tạo hình sành sứ và thủy tinh rất tinh xảo của bàn tay nghệ nhân thời xưa qua, bởi lẽ. Có thể nói lăng Khải Định là một công trình kết hợp độc đáo giữa kiến trúc Đông – Tây tinh xảo.', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 16.397, 107.571, 'historical', '["http://surl.li/wavyrq"]', 4.5, 874, '06:30 summer; 07:00 ', '18:00 summer; 17:30 ', 150000, '["thời Nguyễn","tạo hình","sành sứ","thủy tinh."]');
INSERT INTO `destinations` VALUES (129, 'Lăng Minh Mạng', 'Lăng Minh Mạng còn gọi là Hiếu Lăng, nằm trên núi Cẩm Khê, gần ngã ba Bằng Lãng là nơi hội lưu của hai dòng Hữu Trạch và Tả Trạch hợp thành sông Hương, cách cố đô Huế 12 km. Lăng Minh Mạng được xây dựng từ năm 1840 đến năm 1843 thì hoàn thành, huy động tới mười nghìn thợ và lính.', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 16.3869, 107.5695, 'historical', '["http://surl.li/pkhszj"]', 5, 295, '07:00', '17:30', 150000, '["Cẩm Khê","nghìn thợ"]');
INSERT INTO `destinations` VALUES (130, 'Cầu Tràng Tiền', 'Một trong những chiếc cầu lâu đời tại Huế và trở thành biểu tượng du lịch của Huế không ai khác chính là cầu Tràng Tiền bắc qua sông Hương thơ mộng cũng là một “nàng thơ” kiều diễm của không ít văn nghệ sĩ trong nước.', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 'Thừa Thiên Huế', 16.4692, 107.5885, 'checkin', '["http://surl.li/cduiat"]', 4.5, 957, '00:00', '23:59', 0, '["biểu tượng","lâu đời"]');
INSERT INTO `destinations` VALUES (131, 'Biển Tân Thành', 'với làn nước trong xanh và bãi cát trắng, biển Tân Thành sở hữu vẻ đẹp rất riêng với bãi cát đen dài hơn 7km. Dọc theo bãi biển là cầu cảng màu xanh lam đặc trưng và các khu lưới người dân dựng lên để đánh bắt cá, nghêu…
INSERT INTO `destinations` VALUES (132, 'Cầu Mỹ Thuận', 'Sau 03 năm thi công, cầu Mỹ Thuận được khánh thành vào năm 2000 và là cây cầu dây văng đầu tiên tại Việt Nam. Với kiến trúc đồ sộ, độc đáo, cây cầu đã trở thành địa điểm check-in của bao thế hệ. Dù bạn di chuyển bằng xe máy hay ô tô thì cũng đều có thể sắp xếp lịch trình đi ngang đây và chiêm ngưỡng vẻ đẹp của cây cầu. Đặc biệt, khi màn đêm buông xuống thì cầu sẽ trở nên nổi bật hơn với hệ thống đèn chiếu sáng và trang trí đấy!
INSERT INTO `destinations` VALUES (133, 'Nhà Thờ Cái Bè', 'Sở hữu nét kiến trúc Roman đặc trưng, nhà thờ Cái Bè không những đóng vai trò quan trọng trong đời sống tôn giáo của người dân nơi đây mà còn là địa điểm tham quan hấp dẫn ở Tiền Giang. Điểm nổi bật nhất của nhà thờ Cái Bè là tháp chuông được xem là cao nhất khu vực Đồng bằng Sông Cửu Long. Ngoài ra, chính diện nhà thờ hướng ra ngã ba sông Cái Bè tựa như đang ôm trọn đất trời. Khuôn viên được bố trí nhiều cây xanh, mang đến cảnh quan đẹp mắt', 'Tiền Giang', 'Tiền Giang', 'Tiền Giang', 10.454075, 106.32788, 'religious', '["http://surl.li/noizrb"]', 4, 635, '07:00', '18:00', 0, '["kiến trúc Roman","tôn giáo","tháo chuông"]');
INSERT INTO `destinations` VALUES (134, 'Chùa Linh Thứu', 'Đây là một trong những ngôi chùa có lịch sử lâu đời nhất tại tỉnh Tiền Giang. Đặc biệt hơn, nơi này gắn liền với câu chuyện thoát chết của vua Gia Long được lưu truyền qua nhiều thế hệ. Đây là một trong những ngôi chùa có lịch sử lâu đời nhất tại tỉnh Tiền Giang. Đặc biệt hơn, nơi này gắn liền với câu chuyện thoát chết của vua Gia Long được lưu truyền qua nhiều thế hệ.', 'Tiền Giang', 'Tiền Giang', 'Tiền Giang', 10.457817, 106.361295, 'religious', '["http://surl.li/cdhewg"]', 4, 942, '07:00', '18:00', 0, '["lịch sử","Gia Long","chùa"]');
INSERT INTO `destinations` VALUES (135, 'Nhà thờ Thánh Tòa ', 'Nhà thờ tọa lạc tại số 32 đường Hùng Vương, P.7, TP. Mỹ Tho. Có tuổi đời hơn 100 năm và trải qua nhiều lần trùng tu nhưng nhà thờ chánh tòa Tiền Giang vẫn giữ được nét đẹp cổ kính với những họa tiết tinh xảo và lối kiến trúc Hy Lạp phục hưng đặc trưng.', 'Tiền Giang', 'Tiền Giang', 'Tiền Giang', 10.424554, 106.331299, 'religious', '["http://surl.li/migylg"]', 4.5, 474, '07:00', '18:00', 0, '["hơn 100 năm","trùng tu","tinh xảo","Hy lạp"]');
INSERT INTO `destinations` VALUES (136, 'Chợ Bến Thành', 'Đây là một trong những địa điểm du lịch Thành phố Hồ Chí Minh nổi tiếng nhất nằm ngay trung tâm thành phố và luôn tấp nập người ra vào mua bán, du khách check in mỗi ngày. Chợ Bến Thành buôn bán tất tần tật những mặt hàng từ thực phẩm, vải vóc, quần áo, đồ gia dụng, đặc sản Sài Gòn,… và quan trọng là khu ẩm thực cực kỳ hấp dẫn ở chợ và những góc check in ấn tượng sẽ làm bạn luôn muốn lưu lại nơi đây thật lâu.', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 10.7721, 106.6983, 'food', '["http://surl.li/xyzzzd"]', 4.5, 363, '06:00', '22:00', 0, '["trung tâm","mua bán","chợ"]');
INSERT INTO `destinations` VALUES (137, 'Dinh Đọc Lập', 'Nơi đây đã được công nhận là 1 trong 10 di tích quốc gia đặc biệt của Việt Nam vào năm 2009. Dinh Độc Lập là nơi trưng bày và lưu giữ những hình ảnh, hiện vật giá trị từ những năm của thế kỷ 19 theo từng chủ đề khác nhau. Đặc biệt nơi đây vẫn còn giữ nguyên nội thất của những căn phòng quan trọng như phòng khánh tiết, phòng nội các,....', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 10.777, 106.6953, 'beach', '["http://surl.li/okcots"]', 5, 388, '08:00', '15:30', 40000, '["di tích","trừng bày"]');
INSERT INTO `destinations` VALUES (138, 'Nhà thờ Đức Bà', 'Cũng nằm ngay trung tâm quận 1, nhà thờ Đức Bà là địa điểm du lịch thành phố Hồ Chí Minh mà bạn nhất định phải ghé đến. Nhà thờ Đức Bà là một công trình kiến trúc độc đáo mang đậm phong cách Châu Âu, là nơi sinh hoạt và tổ chức các buổi Thánh lễ cho những người theo đạo Công giáo ở Sài Thành.', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 10.7798, 106.699, 'religious', '["http://surl.li/elnblm"]', 4.8, 528, '07:00', '18:00', 0, '["quận 1","độc đáo"]');
INSERT INTO `destinations` VALUES (139, 'Bảo tàng lịch sử Việt Nam', 'Bảo tàng lịch sử Việt Nam được xây dựng và hoạt động từ những năm đầu thế kỷ 20, là nơi lưu giữ và bảo tồn những hình ảnh, cổ vật từ thuở sơ khai đến nay. Bảo tàng lịch sử Việt Nam thu hút phần lớn những du khách yêu lịch sử và kiến trúc pha trộn giữa 2 phong cách Á – Âu độc đáo.', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 10.7876, 106.7051, 'historical', '["http://surl.li/tvoyhe"]', 4.5, 252, '08:00', '17:00', 30000, '["lịch sử","bảo tồn","cổ vật","Á - Âu"]');
INSERT INTO `destinations` VALUES (140, 'Địa đạo Củ Chi', 'Nơi đây là di tích quốc gia đặc biệt, gắn liền với lịch sử chiến tranh Việt Nam, từng là căn cứ địa quan trọng và cũng là nơi sinh hoạt chung bao gồm bệnh xá, nhà bếp, nơi làm việc,… của quân đội ta trong cuộc kháng chiến chống quân xâm lược, giành lại toàn vẹn lãnh thổ. Bên cạnh đó, bên trong địa đạo Củ Chi còn tái hiện tại cuộc sống của họ qua những qua những mô hình người và vật rất chân thật, ấn tượng. Nơi đây là một trong những điểm đến hấp dẫn của những tour Hồ Chí Minh mà bạn không nên bỏ qua trong chuyến đi của mình.', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 'TP. Hồ Chí Minh', 11.1444, 106.4645, 'historical', '["http://surl.li/ebxvcg"]', 4.5, 134, '07:00', '17:00', 90000, '["di tích","lịch sử","mô hình","ấn tượng."]');
