INSERT INTO `destinations` VALUES (144, 'Miếu Bà Chúa Xứ', 'Miếu Bà Chúa Xứ là một trong những địa điểm tâm linh nổi tiếng nhất An Giang', 'An Giang ', 'An Giang', 'An Giang ', 10.682, 105.0813, 'religious', '["https://s.net.vn/r9Yr"]', 3.1, 1, '07:00', '18:00', 0, '["waterfall","photography","culture","hiking"]');
INSERT INTO `destinations` VALUES (145, 'Núi Dinh Vũng Tàu', 'Núi Dinh nổi bật với những vách đá dựng đứng, tạo nên một bức tranh thiên nhiên hùng vĩ', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 10.615, 107.1435, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQK5hQDfkci2z3IWc-qBxtVU6KPcIMwYRc7lQ&s"]', 4.5, 465, '07:00', '17:00', 0, '["museum","shopping","hiking"]');
INSERT INTO `destinations` VALUES (146, 'Bãi Sau ', 'Bãi Sau được biết đến là một trong những bãi biển đẹp và lớn nhất Việt Nam', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 10.3367, 107.0922, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ7KnCQZ8kVAgofoujsywHu0xyF-NBMyfHidA&s"]', 4.3, 486, '00:00', '23:59', 0, '["nightmarket","photography"]');
INSERT INTO `destinations` VALUES (147, 'Hồ Tràm ', 'Là một trong những bãi biển đẹp nhất khu vực miền Nam', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 10.4648, 107.4318, 'beach', '["https://vcdn1-dulich.vnecdn.net/2024/09/19/cau-Ho-Tram-5872-1726743933.jpg?w=460&h=0&q=100&dpr=2&fit=crop&s=ga2oqi-VuSpZfMneC_YG6Q"]', 4.3, 445, '00:00', '23:59', 0, '["relax","photography","nature"]');
INSERT INTO `destinations` VALUES (148, 'Suối Ồ ', 'Nơi đây nổi tiếng với vẻ đẹp hiếm có, vừa có suối nước ngọt, vừa có bãi biển nước mặn giao hòa trong cùng một khu vực.', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 10.564768, 107.22887, 'beach', '["https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/10_2022/suoi-o-an-giang.jpg"]', 3.5, 686, '00:00', '23:59', 0, '["shopping","camping","temple"]');
INSERT INTO `destinations` VALUES (149, 'Côn Đảo Vũng Tàu', 'Là một quần đảo nổi tiếng với vẻ đẹp thiên nhiên hoang sơ, mà còn mang đậm dấu ấn lịch sử với các di tích gắn liền thời kỳ chiến tranh.', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 'Bà Rịa - Vũng Tàu', 8.6864, 106.6084, 'beach', '["https://condao.com.vn/uploads/news/2023_03/toan-canh-thi-tran-con-dao_1.jpg"]', 4.6, 930, '00:00', '23:59', 0, '["sunset","nature"]');
INSERT INTO `destinations` VALUES (150, 'Chùa cổ Bồ Đà ', 'Là một trong những ngôi chùa cổ nổi tiếng và đặc sắc nhất vùng Kinh Bắc', 'Bắc Giang', 'Bắc Giang', 'Bắc Giang', 21.263725, 106.162535, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRS1BhO9oORxURb02dkvJIwVfm1Fy4TQFzJdg&s"]', 4.5, 68, '07:00', '18:00', 0, '["nightmarket","nature"]');
