INSERT INTO `destinations` VALUES (153, 'Đền Trung', 'Đây là một trong ba ngôi đền chính thờ các vua Hùng và gắn liền với truyền thuyết dựng nước của dân tộc Việt Nam', 'Bắc Giang', 'Bắc Giang', 'Bắc Giang', 21.28763, 106.184045, 'religious', '["https://static.vinwonders.com/production/den-trung-ba-vi-6.jpg"]', 3.8, 1, '07:00', '18:00', 0, '["camping","themepark","nature","relax"]');
INSERT INTO `destinations` VALUES (154, 'Hồ Khuôn Thần', 'Là một điểm đến lý tưởng với vẻ đẹp thiên nhiên thơ mộng và không khí trong lành', 'Bắc Giang', 'Bắc Giang', 'Bắc Giang', 21.28688, 106.21766, 'nature', '["https://media.mybacgiang.vn/resources/portal//Images/BGG/annn.bgg/%C4%90%E1%BB%8Ba%20%C4%91i%E1%BB%83m/H%E1%BB%93%20Khu%C3%B4n%20Th%E1%BA%A7n/136958118051a2267c8942b_636828172277177207.jpg"]', 4.8, 437, '07:00', '17:00', 0, '["shopping","swim","relax","coffee"]');
