INSERT INTO `destinations` VALUES (156, 'Thác Đầu Đẳng', 'Đây là địa điểm du lịch sinh thái lý tưởng.', 'Bắc Kạn', 'Bắc Kạn', 'Bắc Kạn', 22.3867, 105.6528, 'nature', '["https://ik.imagekit.io/tvlk/blog/2022/10/thac-dau-dang-1.jpg?tr=dpr-2,w-675"]', 4.3, 175, '07:00', '17:00', 0, '["island","citywalk","shopping"]');
INSERT INTO `destinations` VALUES (157, 'Bản Pác Ngòi', 'Đây là một bản làng của người Tày, nổi bật với nét văn hóa truyền thống', 'Bắc Kạn', 'Bắc Kạn', 'Bắc Kạn', 22.142118, 105.790066, 'culture', '["https://ik.imagekit.io/tvlk/blog/2023/11/ban-pac-ngoi-2.jpg?tr=dpr-2,w-675"]', 4.6, 71, '07:00', '17:00', 0, '["sunset","camping","nature"]');
INSERT INTO `destinations` VALUES (158, 'Động Nàng Tiên', 'Đây là một hang động kỳ vĩ với thạch nhũ hình dạng đa dạng, gắn liền với truyền thuyết về nàng tiên xinh đẹp.', 'Bắc Kạn', 'Bắc Kạn', 'Bắc Kạn', 22.185326, 105.868447, 'nature', '["https://ik.imagekit.io/tvlk/blog/2023/11/dong-nang-tien-4.png?tr=dpr-2,w-675"]', 4.2, 832, '07:00', '17:00', 0, '["food","themepark","shopping"]');
INSERT INTO `destinations` VALUES (159, 'Chùa Quan Đế      ', 'Là một ngôi chùa cổ kính, thờ Quan Công – một vị tướng nổi tiếng trong lịch sử Trung Quốc', 'Bạc Liêu', 'Bạc Liêu', 'Bạc Liêu', 9.279003, 105.728117, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR3TOKOlNtvhExvWc2nlN8dZ6yeyH9KKd1kPw&s"]', 4.4, 187, '07:00', '18:00', 0, '["photography","temple"]');
INSERT INTO `destinations` VALUES (160, 'Biển Bạc Liêu', 'Biển Bạc Liêu có bờ biển dài, là một điểm đến du lịch nghỉ dưỡng tuyệt vời tại miền Tây Nam Bộ', 'Bạc Liêu', 'Bạc Liêu', 'Bạc Liêu', 9.309181, 105.71329, 'beach', '["https://mia.vn/media/uploads/blog-du-lich/bien-bac-lieu-dep-1699487868.jpg"]', 3.3, 157, '00:00', '23:59', 0, '["themepark","nightmarket","food"]');
INSERT INTO `destinations` VALUES (161, 'Cây Xoài Cổ Thụ', 'Đây là cây xoài lớn tuổi, được xem là biểu tượng của sự trường thọ và thịnh vượng.', 'Bạc Liêu', 'Bạc Liêu', 'Bạc Liêu', 9.292209, 105.754741, 'attraction', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRdKmG6YklkV9Ez1d2Dl2jpE5oJ02SO6vT6gw&s"]', 4.4, 411, '07:00', '17:30', 0, '["shopping","themepark","food","street_food"]');
INSERT INTO `destinations` VALUES (162, 'Nhà Công tử Bạc Liêu', 'Ngôi nhà này từng là nơi sinh sống của công tử Bạc Liêu, một nhân vật nổi tiếng trong lịch sử.', 'Bạc Liêu', 'Bạc Liêu', 'Bạc Liêu', 9.2946, 105.7286, 'historical', '["https://ik.imagekit.io/tvlk/blog/2023/03/nha-cong-tu-bac-lieu-1.jpg?tr=dpr-2,w-675"]', 4.3, 1, '07:00', '17:00', 0, '["camping","museum","island"]');
INSERT INTO `destinations` VALUES (163, 'Đồng Hồ Thái Dương', 'Đồng Hồ Thái Dương là một công trình kiến trúc đặc biệt tại Hà Nội, mang ý nghĩa biểu tượng về thời gian và vũ trụ.', 'Bạc Liêu', 'Bạc Liêu', 'Bạc Liêu', 9.332539, 105.73378, 'nature', '["https://filedltpbl.baclieu.gov.vn//Upload/NewsImage/R637964323666900687.png"]', 4.8, 132, '07:00', '17:00', 0, '["boat","swim"]');
INSERT INTO `destinations` VALUES (164, 'Chùa Phật Tích    ', 'Đây là một trong những ngôi chùa cổ, gắn liền với lịch sử Phật giáo Việt Nam.', 'Bắc Ninh', 'Bắc Ninh', 'Bắc Ninh', 21.14865, 106.10125, 'religious', '["https://owa.bestprice.vn/images/destinations/uploads/chua-phat-tich-600fc98393ec1.jpg"]', 4.3, 714, '07:00', '18:00', 0, '["hiking","shopping"]');
INSERT INTO `destinations` VALUES (165, 'Chùa Bút Tháp', 'Chùa Bút Tháp nằm ở Bắc Ninh, là một ngôi chùa nổi tiếng với kiến trúc độc đáo và tượng Phật Bà Quan Âm.', 'Bắc Ninh', 'Bắc Ninh', 'Bắc Ninh', 21.087, 106.037, 'religious', '["https://bacninh.gov.vn/documents/135051/27556595/Butthap1.jpg/715b96c9-a9ab-43b6-ae18-8f7424283cf0?t=1599724975786"]', 4.6, 218, '07:00', '18:00', 0, '["boat","waterfall","food"]');
INSERT INTO `destinations` VALUES (166, 'Làng tranh Đông Hồ', 'Làng tranh Đông Hồ ở Bắc Ninh là nơi sản xuất tranh dân gian nổi tiếng, với những bức tranh phản ánh đời sống nông thôn Việt Nam.', 'Bắc Ninh', 'Bắc Ninh', 'Bắc Ninh', 21.0695, 106.0757, 'nature', '["https://gaohouse.vn/wp-content/uploads/2024/07/lang-tranh-dong-ho.jpg"]', 4.9, 714, '07:00', '17:00', 0, '["culture","relax","nightmarket","temple"]');
INSERT INTO `destinations` VALUES (167, 'Đền bà Chúa Kho', 'Đền Bà Chúa Kho ở Bắc Ninh là nơi thờ bà Chúa Kho, một trong những vị thần được thờ cúng linh thiêng nhất ở Việt Nam', 'Bắc Ninh', 'Bắc Ninh', 'Bắc Ninh', 21.1701, 106.0906, 'religious', '["https://denbachuakho.com.vn/wp-content/uploads/2021/09/den-ba-chua-kho-tho-ai.jpg"]', 4.1, 906, '07:00', '18:00', 0, '["nature","camping","boat"]');
INSERT INTO `destinations` VALUES (168, 'Chợ Ninh Hiệp', 'Chợ Ninh Hiệp là một trong những khu chợ nổi tiếng nhất miền Bắc, chuyên buôn bán các mặt hàng vải vóc, quần áo.', 'Bắc Ninh', 'Bắc Ninh', 'Bắc Ninh', 21.210834, 106.065473, 'food', '["https://davitrans.com/images/2020/10/27/cho-ninh-hiep-hn.jpg"]', 4.7, 1, '06:00', '22:00', 0, '["nightmarket","island","food"]');
INSERT INTO `destinations` VALUES (169, 'khu du lịch Cồn Phụng    ', 'Cồn Phụng nằm ở Bến Tre, nổi bật với phong cảnh sông nước miệt vườn, vườn dừa và các hoạt động du lịch sinh thái.', 'Bến Tre  ', 'Bến Tre', 'Bến Tre  ', 10.230047, 106.405778, 'attraction', '["https://gaohouse.vn/wp-content/uploads/2023/07/khu_du_lich_con_phung_de3cc60e04844e7da58abea32a4ddecd_grande.jpg"]', 4.9, 656, '07:00', '17:30', 0, '["street_food","waterfall","hiking"]');
INSERT INTO `destinations` VALUES (170, ' Khu lăng mộ cụ Nguyễn Đình Chiểu', 'Khu lăng mộ Nguyễn Đình Chiểu ở Bến Tre là nơi yên nghỉ của nhà thơ, nhà văn nổi tiếng.', 'Bến Tre  ', 'Bến Tre', 'Bến Tre  ', 10.230945, 106.338642, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQRzKE0ChEgtsYxNyAIp89N1Cd1UxZjo_2-7w&s"]', 3.4, 1, '07:00', '17:00', 0, '["nightmarket","island","culture","shopping"]');
INSERT INTO `destinations` VALUES (171, 'Chùa Tuyên Linh', 'Chùa Tuyên Linh ở Quảng Ninh là một ngôi chùa nổi tiếng với cảnh quan yên bình và kiến trúc đặc sắc.', 'Bến Tre  ', 'Bến Tre', 'Bến Tre  ', 10.282802, 106.397337, 'religious', '["https://baocantho.com.vn/image/fckeditor/upload/2024/20240526/images/Anh%201%20(40).webp"]', 4.6, 615, '07:00', '18:00', 0, '["culture","waterfall","camping"]');
INSERT INTO `destinations` VALUES (172, 'Nhà thờ La Mã', 'Nhà thờ La Mã ở Hà Nội là một công trình kiến trúc phương Tây, nổi bật với phong cách gothic đặc trưng.', 'Bến Tre  ', 'Bến Tre', 'Bến Tre  ', 10.193832, 106.387599, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRYWPE1YGk-lQofS0oFZKX9ycbGzCixlhMD7w&s"]', 4.7, 476, '07:00', '18:00', 0, '["hiking","coffee"]');
INSERT INTO `destinations` VALUES (173, ' Khu du lịch sinh thái vườn Ba Ngói', 'Là khu du lịch sinh thái nổi bật ở Bến Tre, thu hút du khách với không gian xanh mát, thiên nhiên hoang sơ và các hoạt động vui chơi giải trí hấp dẫn.', 'Bến Tre  ', 'Bến Tre', 'Bến Tre  ', 10.251766, 106.36315, 'theme_park', '["https://mia.vn/media/uploads/blog-du-lich/khu-du-lich-vuon-ba-ngoi-voi-khong-gian-song-nuoc-huu-tinh-3-1667357530.jpg"]', 4.1, 1, '08:00', '18:00', 200000, '["food","museum","shopping"]');
INSERT INTO `destinations` VALUES (174, 'Bãi tắm Quy Nhơn ', 'Bãi tắm Quy Nhơn là một trong những bãi biển đẹp của miền Trung, nổi tiếng với cát trắng mịn và nước biển trong xanh.', 'Bình Định', 'Bình Định', 'Bình Định', 13.785137, 109.240664, 'beach', '["https://quynhontourist.com/wp-content/uploads/2019/01/kinh-nghiem-du-lich-quy-nhon-1-ngay-quy-nhon-tourist.jpg"]', 4.1, 525, '00:00', '23:59', 0, '["nature","coffee"]');
INSERT INTO `destinations` VALUES (175, ' Biển Kỳ Co', 'Biển Kỳ Co thuộc Quy Nhơn, nổi tiếng với bãi biển hoang sơ, nước trong xanh và các rạn san hô đẹp mắt', 'Bình Định', 'Bình Định', 'Bình Định', 13.760992, 109.202939, 'beach', '["https://cdnphoto.dantri.com.vn/75MTzLTi_7Ys_reS6Va31bGWBk4=/zoom/1200_630/2018/7/1/anh-1-1530460120717428571836.jpg"]', 4.4, 542, '00:00', '23:59', 0, '["nightmarket","swim"]');
INSERT INTO `destinations` VALUES (176, 'Cù Lao Xanh', 'Cù Lao Xanh là một hòn đảo đẹp và hoang sơ tại Bình Định, với làn nước trong xanh và thiên nhiên chưa bị khai thác nhiều.', 'Bình Định', 'Bình Định', 'Bình Định', 13.814936, 109.217842, 'beach', '["https://ik.imagekit.io/tvlk/blog/2022/09/cu-lao-xanh-1.jpg?tr=dpr-2,w-675"]', 4.3, 820, '00:00', '23:59', 0, '["photography","swim","camping","nightmarket"]');
INSERT INTO `destinations` VALUES (177, 'Đầm Thị Nại', 'Đầm Thị Nại ở Bình Định là một trong những đầm lớn của miền Trung, nổi bật với khung cảnh thiên nhiên tĩnh lặng', 'Bình Định', 'Bình Định', 'Bình Định', 13.754942, 109.247986, 'attraction', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTUVFCT7Ph_xMd2qiDsSVKhK13rCp9sJ6YrNA&s"]', 4.4, 348, '07:00', '17:30', 0, '["boat","relax","hiking","culture"]');
INSERT INTO `destinations` VALUES (178, ' Hòn Khô', 'Hòn Khô là một hòn đảo nhỏ nằm gần Quy Nhơn, nổi tiếng với các bãi biển đẹp và làn nước trong vắt, thu hút du khách đến tham quan và tắm biển.', 'Bình Định', 'Bình Định', 'Bình Định', 13.783131, 109.174914, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTjXjzOeHXgs6ds_2TKhzmOJm-OJL7Ns6dAGw&s"]', 4.5, 2, '00:00', '23:59', 0, '["sunset","museum","temple","coffee"]');
INSERT INTO `destinations` VALUES (179, 'Chùa Tây Tạng    ', 'Chùa Tây Tạng là một ngôi chùa nổi tiếng ở Bình Dương, thu hút du khách bởi kiến trúc độc đáo và không gian thanh tịnh.', 'Bình Dương', 'Bình Dương', 'Bình Dương', 11.013894, 106.69036, 'religious', '["https://bizweb.dktcdn.net/100/405/413/articles/ngoi-chua-tay-tang-thu-dau-mot-binh-duong.jpg?v=1695654021547"]', 4.7, 575, '07:00', '18:00', 0, '["sunset","coffee","culture"]');
INSERT INTO `destinations` VALUES (180, 'Khu du lịch Đại Nam', 'Khu du lịch Đại Nam là một khu phức hợp bao gồm công viên, khu vui chơi, và các điểm tham quan khác, nổi bật tại Bình Dương, thu hút nhiều du khách đến tham quan và giải trí.', 'Bình Dương', 'Bình Dương', 'Bình Dương', 11.0561, 106.6681, 'theme_park', '["https://trainghiem.vn/blog/wp-content/uploads/2022/02/1-khu-vui-choi-giai-tri-dai-nam.jpg"]', 4.3, 1, '08:00', '18:00', 200000, '["photography","street_food","citywalk","themepark"]');
INSERT INTO `destinations` VALUES (181, 'Công viên Thành Phố mới Bình Dương', 'Công viên Thành Phố mới Bình Dương là một không gian xanh, là nơi lý tưởng cho các hoạt động thể thao, dạo bộ và thư giãn.', 'Bình Dương', 'Bình Dương', 'Bình Dương', 10.97503, 106.678361, 'theme_park', '["https://mia.vn/media/uploads/blog-du-lich/kham-pha-cong-vien-thanh-pho-moi-binh-duong-voi-nhung-trai-nghiem-sieu-thu-vi-1-1654574759.jpg"]', 4.6, 865, '08:00', '18:00', 200000, '["citywalk","hiking","museum","coffee"]');
INSERT INTO `destinations` VALUES (182, 'Chùa Châu Thới', 'Chùa Châu Thới là một ngôi chùa nổi tiếng ở Bình Dương, mang đậm nét văn hóa Phật giáo và có khung cảnh thanh tịnh, phù hợp cho các hoạt động tham quan tâm linh.', 'Bình Dương', 'Bình Dương', 'Bình Dương', 10.9, 106.784, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRyIMViYEfkSXvBSYsuWWsypX6RMCzISdUN2Q&s"]', 4.7, 1, '07:00', '18:00', 0, '["culture","photography","museum"]');
INSERT INTO `destinations` VALUES (183, 'Núi Bà Rá   ', 'Ngọn núi cao nhất Bình Phước, có cáp treo dẫn lên đỉnh', 'Bình Phước', 'Bình Phước', 'Bình Phước', 11.814, 106.993, 'nature', '["https://media.baobinhphuoc.com.vn/upload/news/3_2021/b5_12320005032021.jpg"]', 4.2, 599, '07:00', '17:00', 0, '["temple","food","photography"]');
INSERT INTO `destinations` VALUES (184, 'Trảng cỏ Bù Lạch', 'Một cánh đồng cỏ rộng lớn, xanh mướt, được bao quanh bởi những khu rừng nguyên sinh và hồ nước', 'Bình Phước', 'Bình Phước', 'Bình Phước', 11.710756, 106.74323, 'nature', '["https://www.sgtiepthi.vn/wp-content/uploads/2023/06/trang-co-bu-lach-132113.jpg"]', 3.5, 1, '07:00', '17:00', 0, '["hiking","food"]');
INSERT INTO `destinations` VALUES (185, 'Khu di tích Tà Thiết', 'Nơi lưu giữ nhiều dấu ấn lịch sử của chiến tranh Việt Nam, với các di tích như hầm chỉ huy và kho quân khí', 'Bình Phước', 'Bình Phước', 'Bình Phước', 11.769895, 106.67605, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcStyK1QxPdJT9j3sA8TKlv7bOSSKOkSNfsXXw&s"]', 4.3, 245, '07:00', '17:00', 0, '["waterfall","nature","food"]');
INSERT INTO `destinations` VALUES (186, 'Hồ Thác Mơ', 'Hồ nhân tạo lớn với cảnh quan thiên nhiên đẹp mắt', 'Bình Phước', 'Bình Phước', 'Bình Phước', 11.756573, 106.737505, 'nature', '["https://mia.vn/media/uploads/blog-du-lich/ho-thuy-dien-thac-mo-diem-du-lich-tu-tuc-cho-nhung-kham-pha-tuyet-voi-1656424836.jpg"]', 4.3, 600, '07:00', '17:00', 0, '["waterfall","nightmarket","museum","shopping"]');
INSERT INTO `destinations` VALUES (187, 'Làng nghề điều Bình Phước', 'Bình Phước nổi tiếng là thủ phủ của điều, nơi du khách có thể tham quan các làng nghề chế biến hạt điều truyền thống và tìm hiểu quy trình sản xuất.', 'Bình Phước', 'Bình Phước', 'Bình Phước', 11.73241, 106.714123, 'culture', '["https://danviet.mediacdn.vn/zoom/600_315/296231569849192448/2022/4/20/vuon-dieu-2-16504549834621494202370-137-67-625-1000-crop-1650455485523479128526.jpg"]', 4.6, 267, '07:00', '17:00', 0, '["camping","street_food"]');
INSERT INTO `destinations` VALUES (188, 'Tháp Chàm Poshanư', 'Công trình kiến trúc cổ của người Chăm, mang giá trị lịch sử và văn hóa đặc sắc', 'Bình Thuận', 'Bình Thuận', 'Bình Thuận', 10.9489, 108.1756, 'historical', '[" q"]', 4.4, 768, '07:00', '17:00', 0, '["hiking","street_food"]');
INSERT INTO `destinations` VALUES (189, 'Hải đăng Kê Gà', ' Một trong những ngọn hải đăng lâu đời nhất Việt Nam, nằm trên một hòn đảo nhỏ giữa biển', 'Bình Thuận', 'Bình Thuận', 'Bình Thuận', 10.7016, 107.9881, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRxa7SzvqYuT8ZjhCcm7N3DyjfMyTL3BdJUuw&s"]', 4.3, 841, '00:00', '23:59', 0, '["camping","nightmarket","coffee","museum"]');
INSERT INTO `destinations` VALUES (190, 'Bàu Trắng', 'Hồ nước ngọt lớn giữa vùng cát trắng, còn gọi là "tiểu sa mạc Sahara" của Việt Nam.', 'Bình Thuận', 'Bình Thuận', 'Bình Thuận', 11.084, 108.431, 'nature', '["https://ik.imagekit.io/tvlk/blog/2023/02/khu-du-lich-bao-trang-2.jpg?tr=dpr-2,w-675"]', 4.7, 587, '07:00', '17:00', 0, '["street_food","temple"]');
INSERT INTO `destinations` VALUES (191, 'Làng Chài Mũi Né', 'Khu vực làng chài truyền thống ven biển, nơi bạn có thể ngắm cảnh thuyền ghe tấp nập và trải nghiệm mua hải sản tươi sống trực tiếp từ ngư dân.', 'Bình Thuận', 'Bình Thuận', 'Bình Thuận', 10.969449, 108.1268, 'beach', '["https://mia.vn/media/uploads/blog-du-lich/ghe-tham-lang-chai-mui-ne-binh-yen-va-day-tho-mong-1657634723.jpg"]', 3.4, 1, '00:00', '23:59', 0, '["island","nightmarket"]');
INSERT INTO `destinations` VALUES (192, 'Hòn Rơm', 'Bãi biển nổi tiếng với làn nước trong xanh, bờ cát dài mịn và không khí yên bình', 'Bình Thuận', 'Bình Thuận', 'Bình Thuận', 10.882574, 108.105278, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSGLlkBsaPyFKARJzCxv_mll17BY3bsJcyS4w&s"]', 4.5, 562, '00:00', '23:59', 0, '["island","museum"]');
INSERT INTO `destinations` VALUES (193, 'Mũi Cà Mau', 'Điểm cực Nam của Việt Nam, nơi có biểu tượng cột mốc quốc gia và hệ sinh thái rừng ngập mặn độc đáo', 'Cà Mau', 'Cà Mau', 'Cà Mau', 8.6218, 104.7295, 'beach', '["https://diemdenantoan.sgtiepthi.vn/wp-content/uploads/2023/08/muicamau-9.jpg"]', 4.1, 1, '00:00', '23:59', 0, '["coffee","waterfall"]');
INSERT INTO `destinations` VALUES (194, 'Vườn Quốc Gia U Minh Hạ', 'Khu rừng tràm ngập nước nổi tiếng với hệ sinh thái đa dạng. Đây là nơi sinh sống của nhiều loài động, thực vật quý hiếm', 'Cà Mau', 'Cà Mau', 'Cà Mau', 9.249, 104.979, 'nature', '["https://hanoitourist.com.vn/uploaded/images/2020/02/kin-nghiem-du-lich-u-minh-ha-3.jpg"]', 4.9, 195, '07:00', '17:00', 0, '["boat","culture"]');
INSERT INTO `destinations` VALUES (195, 'Hòn Đá Bạc', 'Cụm đảo nằm sát bờ biển, nổi bật với những phiến đá xếp chồng tự nhiên và hệ sinh thái biển phong phú', 'Cà Mau', 'Cà Mau', 'Cà Mau', 9.158243, 105.132788, 'beach', '["https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/07_2020/noi-day-duoc-menh-danh-la-bien-ho-giua-dong-bang.jpg"]', 4.3, 556, '00:00', '23:59', 0, '["nature","hiking","nightmarket"]');
INSERT INTO `destinations` VALUES (196, 'Đầm Thị Tường', 'Được mệnh danh là “biển hồ giữa đồng bằng”, đây là đầm nước tự nhiên lớn nhất miền Tây', 'Cà Mau', 'Cà Mau', 'Cà Mau', 9.209716, 105.154755, 'beach', '["https://dulichtravinh.com.vn/wp-content/uploads/2021/01/605a0a3db40c76522f1d.jpg"]', 4.7, 260, '00:00', '23:59', 0, '["relax","nature","island"]');
INSERT INTO `destinations` VALUES (197, 'Đền Thờ Bác Hồ', 'Địa điểm tâm linh quan trọng, nơi người dân Cà Mau bày tỏ lòng thành kính với Chủ tịch Hồ Chí Minh', 'Cà Mau', 'Cà Mau', 'Cà Mau', 9.146236, 105.176625, 'religious', '["https://bizweb.dktcdn.net/100/366/377/files/hinh-anh-cho-noi-cai-rang.jpg?v=1681008363485"]', 4.8, 937, '07:00', '18:00', 0, '["street_food","food"]');
INSERT INTO `destinations` VALUES (198, 'Chợ Nổi Cái Răng', 'Chợ nổi lớn và nổi tiếng nhất ở miền Tây Nam Bộ, nơi buôn bán nhộn nhịp trên sông. Du khách có thể trải nghiệm văn hóa sông nước, mua sắm đặc sản và thưởng thức ẩm thực trên thuyền.', 'Cần Thơ', 'Cần Thơ', 'Cần Thơ', 10.0021, 105.7677, 'food', '["https://vemekong.com/wp-content/uploads/2021/04/can-tho-bridge-vietnam-7a-1024x576.jpg"]', 4.2, 576, '06:00', '22:00', 0, '["island","photography","relax","coffee"]');
INSERT INTO `destinations` VALUES (199, 'Cầu Cần Thơ', 'Cây cầu dây văng lớn nhất Đông Nam Á, nối liền Cần Thơ và Vĩnh Long. Đây là điểm check-in nổi tiếng và mang tính biểu tượng của vùng đất Tây Nam Bộ.', 'Cần Thơ', 'Cần Thơ', 'Cần Thơ', 10.0317, 105.8055, 'checkin', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSxyvBpY5_eaRCVeve7UNtEdal3b-tXmfIj6g&s"]', 4.3, 572, '00:00', '23:59', 0, '["themepark","waterfall","citywalk","coffee"]');
INSERT INTO `destinations` VALUES (200, 'Làng Du Lịch Sinh Thái Ông Đề', 'Điểm đến hấp dẫn với cảnh quan xanh mát, các trò chơi dân gian, chèo thuyền, và thưởng thức các món ăn đặc sản miền Tây.', 'Cần Thơ', 'Cần Thơ', 'Cần Thơ', 10.030653, 105.74324, 'food', '["https://thamhiemmekong.com/wp-content/uploads/2019/05/Ch%C3%B9a_%C3%94ng_C%E1%BA%A7n_Th%C6%A1.jpg"]', 4.1, 1, '06:00', '22:00', 0, '["waterfall","food","culture","nightmarket"]');
INSERT INTO `destinations` VALUES (201, 'Chùa Ông', 'Ngôi chùa cổ mang kiến trúc Trung Hoa, nổi tiếng linh thiêng và là nơi thờ Quan Công. Đây là địa điểm tham quan văn hóa độc đáo và check-in đẹp.', 'Cần Thơ', 'Cần Thơ', 'Cần Thơ', 10.034, 105.7885, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS-X0nitGgMoDdl872gvoX7O36J24UYtatnQw&s"]', 4.6, 102, '07:00', '18:00', 0, '["hiking","nature","boat","culture"]');
INSERT INTO `destinations` VALUES (202, 'Cồn Sơn', 'Khu sinh thái sông nước nổi tiếng, nơi du khách có thể tham quan làng cá bè, học làm bánh dân gian và trải nghiệm lối sống miệt vườn.', 'Cần Thơ', 'Cần Thơ', 'Cần Thơ', 10.036347, 105.772407, 'culture', '["https://dulichviet.com.vn/images/bandidau/review-tron-bo-kinh-nghiem-du-lich-con-son-can-tho-cuc-chi-tiet.jpg"]', 4.3, 102, '07:00', '17:00', 0, '["boat","hiking"]');
INSERT INTO `destinations` VALUES (203, 'Thác Bản Giốc', 'Một trong những thác nước đẹp nhất và lớn nhất Đông Nam Á, nằm trên biên giới Việt Nam - Trung Quốc. Thác được chia thành nhiều tầng với dòng nước trong xanh, tạo nên khung cảnh hùng vĩ.', 'Cao Bằng ', 'Cao Bằng', 'Cao Bằng ', 22.8554, 106.7214, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR8q5L6WXqDFFhtORzBnJg_oAuNoZL_HOk12A&s"]', 4.6, 871, '07:00', '17:00', 45000, '["hiking","citywalk","nature"]');
INSERT INTO `destinations` VALUES (204, 'Động Ngườm Ngao', 'Hang động dài hơn 2.1km, nổi bật với hệ thống thạch nhũ độc đáo và cảnh quan kỳ ảo. Động nằm gần thác Bản Giốc, là điểm đến lý tưởng để khám phá.', 'Cao Bằng ', 'Cao Bằng', 'Cao Bằng ', 22.8522, 106.7258, 'nature', '["https://www.kynghidongduong.vn/userfiles/images/tour-trong-nuoc/ba-be-ban-gioc/dong-nguom-ngao-du-lich-thac-ban-gioc-kynghidongduong-003.jpg"]', 4.6, 697, '07:00', '17:00', 45000, '["culture","nightmarket"]');
INSERT INTO `destinations` VALUES (205, 'Núi Mắt Thần', 'Ngọn núi độc đáo với một lỗ lớn ở giữa, được gọi là "Mắt Thần." Đây là điểm check-in nổi tiếng với cảnh quan núi non tuyệt đẹp.', 'Cao Bằng ', 'Cao Bằng', 'Cao Bằng ', 22.72, 106.405, 'nature', '["https://cdn.tuoitre.vn/zoom/700_700/2020/2/7/thu4-read-only-15810754865291338931220-crop-1581075584794374189472.jpg"]', 3.7, 1, '07:00', '17:00', 0, '["food","coffee","photography","boat"]');
INSERT INTO `destinations` VALUES (206, 'Di tích rừng Trần Hưng Đạo', 'Nơi thành lập Đội Việt Nam Tuyên Truyền Giải Phóng Quân năm 1944, khởi nguồn của Quân đội Nhân dân Việt Nam. Khu di tích có giá trị lịch sử to lớn.', 'Cao Bằng ', 'Cao Bằng', 'Cao Bằng ', 22.691459, 106.219369, 'historical', '["https://images.vietnamtourism.gov.vn/vn//images/2019/Thang10/Rung-THD5.jpg"]', 4.4, 691, '07:00', '17:00', 0, '["photography","camping"]');
INSERT INTO `destinations` VALUES (207, 'Làng rèn Phúc Sen', 'Làng nghề truyền thống nổi tiếng với sản phẩm dao kéo chất lượng cao. Du khách có thể tham quan quy trình rèn và mua sắm các sản phẩm thủ công.', 'Cao Bằng ', 'Cao Bằng', 'Cao Bằng ', 22.670056, 106.278496, 'culture', '["https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/03_2023/lang-ren-phuc-sen-8.jpg"]', 4.2, 484, '07:00', '17:00', 0, '["photography","street_food","culture"]');
INSERT INTO `destinations` VALUES (208, 'Bà Nà Hills', 'Khu nghỉ dưỡng trên đỉnh núi với khí hậu mát mẻ, nổi tiếng với cây Cầu Vàng độc đáo, làng Pháp cổ điển và khu vui chơi trong nhà Fantasy Park.', 'Đà Nẵng', 'Đà Nẵng', 'Đà Nẵng', 15.9989, 107.9953, 'theme_park', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTM6kdP5kHtS7vvCKTyaUeiWlHxo7LRW9HAeg&s"]', 4.6, 625, '08:00', '22:00', 1000000, '["shopping","food","island"]');
INSERT INTO `destinations` VALUES (209, 'Cầu Rồng', 'Biểu tượng của thành phố Đà Nẵng, cây cầu có thiết kế hình rồng phun lửa và nước vào cuối tuần. Đây là điểm check-in và ngắm cảnh sông Hàn tuyệt đẹp.', 'Đà Nẵng', 'Đà Nẵng', 'Đà Nẵng', 16.06063, 108.22996, 'checkin', '["https://furamavietnam.com/wp-content/uploads/2024/11/Furama-Resort-Danang-Sightseeing-Dragon-Brigde-2-1024x576.jpg"]', 4.3, 667, 'All day; fire/water ', 'All day; show ends 2', 0, '["coffee","relax","culture","hiking"]');
INSERT INTO `destinations` VALUES (210, 'Ngũ Hành Sơn', 'Cụm núi đá vôi gồm 5 ngọn núi với hang động, chùa chiền, và khung cảnh thiên nhiên tuyệt đẹp. Nổi bật là động Huyền Không và chùa Tam Thai.', 'Đà Nẵng', 'Đà Nẵng', 'Đà Nẵng', 15.995506, 108.258805, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQdTi2qoTGuFODJZyhn7dgJ6Oh5zpv8qNKciQ&s"]', 4.7, 286, '07:00', '17:00', 40000, '["photography","museum","culture"]');
INSERT INTO `destinations` VALUES (211, 'Cầu Tình Yêu', 'Cây cầu nhỏ bên sông Hàn với thiết kế lãng mạn, nơi các cặp đôi thường treo móc khóa tình yêu. Từ đây, bạn có thể ngắm nhìn tượng Cá Chép Hóa Rồng.', 'Đà Nẵng', 'Đà Nẵng', 'Đà Nẵng', 16.0644, 108.2306, 'checkin', '["https://flane.vn/wp-content/uploads/2024/03/kham-pha-cau-tinh-yeu-da-nang.jpg"]', 4.2, 430, '00:00', '23:59', 0, '["sunset","swim"]');
INSERT INTO `destinations` VALUES (212, 'Ao bà om', 'Ao Bà Om là một hồ nước tự nhiên, được bao quanh bởi hàng cây cổ thụ hàng trăm năm tuổi với rễ cây nổi lên thành những hình thù kỳ thú. Đây là một địa điểm du lịch yên bình, gắn liền với truyền thuyết và văn hóa Khmer.', 'Trà Vinh', 'Trà Vinh', 'Trà Vinh', 9.883723, 106.343762, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRDwAYvrczPEgIMA3BxZk7FuuDVdr_85Y0Sbg&s"]', 4.3, 1, '07:00', '17:00', 0, '["sunset","camping","coffee"]');
INSERT INTO `destinations` VALUES (213, 'Chùa Hang', 'Chùa Hang nổi tiếng không chỉ vì kiến trúc độc đáo mà còn vì những tác phẩm điêu khắc gỗ tinh xảo của các nghệ nhân Khmer. Ngôi chùa này là điểm dừng chân lý tưởng cho những ai muốn khám phá nghệ thuật và văn hóa Khmer.', 'Trà Vinh', 'Trà Vinh', 'Trà Vinh', 9.9511, 106.3605, 'religious', '["https://dulichnuisam.vn/wp-content/uploads/2023/01/CHUAHANG1-scaled.jpg"]', 4.9, 696, '07:00', '18:00', 0, '["food","museum","hiking","camping"]');
INSERT INTO `destinations` VALUES (214, 'Bãi biển Ba Động', ' bãi biển hoang sơ với cát mịn và sóng nhẹ, Ba Động là nơi thích hợp để thư giãn và thưởng thức các món hải sản tươi ngon. Đây là một trong những bãi biển hiếm hoi ở miền Tây Nam Bộ.', 'Trà Vinh', 'Trà Vinh', 'Trà Vinh', 9.6317, 106.5628, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSIGIWhgylUovF3TjKNq5WlTWXLBj_ZyCNKlQ&s"]', 4.3, 851, '00:00', '23:59', 0, '["themepark","museum"]');
INSERT INTO `destinations` VALUES (215, 'Bảo tàng Văn hóa Khmer', 'Bảo tàng trưng bày các hiện vật, tư liệu về đời sống, văn hóa, nghệ thuật và lịch sử của người Khmer Nam Bộ, giúp du khách hiểu thêm về cộng đồng dân tộc này.', 'Trà Vinh', 'Trà Vinh', 'Trà Vinh', 9.918926, 106.323387, 'historical', '["https://dulichthuduc.com.vn/vnt_upload/news/MIEN-TAY/tra-vinh/bao_tang_van_hoa_dan_toc_khmer_tra_vinh_du_lich_thu_duc_1.jpg"]', 4.1, 671, '07:00', '17:00', 0, '["museum","swim","camping","street_food"]');
INSERT INTO `destinations` VALUES (216, 'Chùa Vàm Rây', 'Là ngôi chùa Khmer lớn nhất Việt Nam, chùa Vàm Rây gây ấn tượng bởi kiến trúc vàng rực rỡ, tượng Phật nằm khổng lồ và không gian tĩnh lặng.', 'Trà Vinh', 'Trà Vinh', 'Trà Vinh', 9.967007, 106.352026, 'religious', '["https://dulichtravinh.com.vn/wp-content/uploads/2021/08/3-Chua-Vam-Ray-XTDLTV-scaled.jpg"]', 4.2, 473, '07:00', '18:00', 0, '["themepark","swim"]');
INSERT INTO `destinations` VALUES (217, 'Thác Bản Ba', 'Thác Bản Ba thuộc xã Trung Hà, huyện Chiêm Hóa, là một cụm thác với 3 tầng chính đổ xuống từ độ cao khoảng 40 m. Thác được bao quanh bởi rừng núi hoang sơ, nước trong xanh và khí hậu mát mẻ quanh năm. Đây là điểm đến lý tưởng để hòa mình vào thiên nhiên.', 'Tuyên Quang', 'Tuyên Quang', 'Tuyên Quang', 21.743177, 105.24793, 'nature', '["https://mia.vn/media/uploads/blog-du-lich/thac-ban-ba-04-1699834746.jpeg"]', 4.3, 59, '07:00', '17:00', 0, '["themepark","citywalk","museum","camping"]');
INSERT INTO `destinations` VALUES (218, 'Hồ Thủy Điện Tuyên Quang', 'Hồ Na Hang được ví như "Hạ Long trên núi", nổi bật với mặt hồ trong xanh, các đảo núi đá vôi trập trùng, và rừng nguyên sinh bao quanh. Du khách có thể khám phá các địa danh như thác Khuổi Nhi, đền Pác Tạ, và tham gia du thuyền ngắm cảnh.', 'Tuyên Quang', 'Tuyên Quang', 'Tuyên Quang', 21.789688, 105.184915, 'beach', '["https://seho.vn/tintuc/wp-content/uploads/2022/04/thuy-dien-tuyen-quang1.jpg"]', 4.6, 192, '00:00', '23:59', 0, '["camping","nature","citywalk"]');
INSERT INTO `destinations` VALUES (219, 'Đền Hạ - Đền Thượng - Đền Ỷ La', 'Đây là ba ngôi đền linh thiêng thuộc thành phố Tuyên Quang, gắn liền với tín ngưỡng thờ Mẫu của người Việt. Các ngôi đền nổi tiếng với kiến trúc cổ kính, không gian trang nghiêm, thu hút đông đảo khách hành hương.', 'Tuyên Quang', 'Tuyên Quang', 'Tuyên Quang', 22.5011, 103.9576, 'beach', '["https://images.vietnamtourism.gov.vn/vn/images/2017/LHDenHa.jpg"]', 4.3, 487, '00:00', '23:59', 0, '["waterfall","shopping","street_food","island"]');
INSERT INTO `destinations` VALUES (220, 'Suối khoáng Mỹ Lâm', 'Suối khoáng Mỹ Lâm nổi tiếng với nguồn nước khoáng nóng tự nhiên, có tác dụng chữa bệnh và thư giãn. Đây là khu du lịch nghỉ dưỡng hấp dẫn, kết hợp giữa trị liệu sức khỏe và cảnh sắc thiên nhiên tươi đẹp.', 'Tuyên Quang', 'Tuyên Quang', 'Tuyên Quang', 21.8194, 105.1646, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTwyfLa6v5N6x6Aok7aGaEoES0PzF30BSiv4g&s"]', 4.7, 615, '07:00', '17:00', 0, '["culture","coffee","photography"]');
INSERT INTO `destinations` VALUES (221, 'Thác Khuổi Nhi', 'hác Khuổi Nhi thuộc khu vực Na Hang, là một trong những thác nước đẹp nhất ở Tuyên Quang. Nước thác trắng xóa đổ xuống từ độ cao lớn, hòa quyện với thiên nhiên hùng vĩ tạo nên cảnh sắc thơ mộng.', 'Tuyên Quang', 'Tuyên Quang', 'Tuyên Quang', 21.796344, 105.220577, 'nature', '["https://top7vietnam.sgtiepthi.vn/wp-content/uploads/2022/08/288795147_3268773303400481_5232539090563656620_n.jpg"]', 4.8, 938, '07:00', '17:00', 0, '["museum","nature","photography"]');
INSERT INTO `destinations` VALUES (222, 'Cù Lao An Bình', 'Cù Lao An Bình là một khu vực miệt vườn đặc trưng của miền Tây Nam Bộ, nổi tiếng với vườn cây ăn trái như chôm chôm, sầu riêng, măng cụt. Du khách có thể tham gia chèo xuồng, tham quan các làng nghề truyền thống và thưởng thức ẩm thực dân dã.', 'Vĩnh Long', 'Vĩnh Long', 'Vĩnh Long', 10.241523, 105.996298, 'food', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSo8bVAfvIhdi7Rohc1LwF3awMwhDQ6U-yUKw&s"]', 47, 249, '06:00', '22:00', 0, '["citywalk","shopping","swim"]');
INSERT INTO `destinations` VALUES (223, 'Chùa Tiên Châu', 'Chùa Tiên Châu nằm trên cù lao An Bình, là một ngôi chùa cổ kính mang đậm nét kiến trúc Phật giáo. Ngôi chùa có không gian yên tĩnh, thanh bình, thu hút nhiều Phật tử và du khách đến chiêm bái.', 'Vĩnh Long', 'Vĩnh Long', 'Vĩnh Long', 21.847, 106.761, 'beach', '["https://dulichvn.org.vn/nhaptin/uploads/images/ditichchuatienchau.jpg"]', 4.3, 355, '00:00', '23:59', 0, '["food","citywalk","street_food"]');
INSERT INTO `destinations` VALUES (224, 'Khu du lịch Vinh Sang', 'Khu du lịch Vinh Sang nằm trên cù lao An Bình, là nơi lý tưởng để trải nghiệm các trò chơi dân gian, tham gia câu cá sấu, chèo xuồng, hoặc khám phá các vườn trái cây.', 'Vĩnh Long', 'Vĩnh Long', 'Vĩnh Long', 10.209478, 105.98053, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSAMYRHq7hfcxBWVme9fvXMBmb-FnXbEt40Cw&s"]', 4.5, 1, '00:00', '23:59', 0, '["camping","museum"]');
INSERT INTO `destinations` VALUES (225, 'Văn Thánh Miếu', 'Văn Thánh Miếu là một công trình cổ kính, mang ý nghĩa tôn vinh Nho học và các bậc hiền tài. Khuôn viên miếu có nhiều cây xanh, tạo không gian yên tĩnh, thanh bình.', 'Vĩnh Long', 'Vĩnh Long', 'Vĩnh Long', 10.284279, 105.931384, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ6ZLRmHxKAL8nQ6GEnc1avbYj_bDxiFvBKPg&s"]', 4.3, 402, '07:00', '18:00', 0, '["citywalk","museum","coffee"]');
INSERT INTO `destinations` VALUES (226, 'Tam Đảo', 'Tam Đảo là khu nghỉ dưỡng nổi tiếng với khí hậu mát mẻ quanh năm, tọa lạc trên dãy núi Tam Đảo. Nơi đây có nhiều điểm tham quan như Tháp Truyền Hình, Nhà Thờ Đá, và chợ đêm Tam Đảo. Du khách có thể tận hưởng cảnh đẹp núi non và ẩm thực địa phương.', 'Vĩnh Phúc', 'Vĩnh Phúc', 'Vĩnh Phúc', 21.4567, 105.6458, 'food', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRprv_3BsUfM_Bu9DQrCo3VUSDatb5a73--PQ&s"]', 4.4, 89, '06:00', '22:00', 0, '["food","themepark","museum","boat"]');
INSERT INTO `destinations` VALUES (227, 'Hồ Đại Lải', 'Hồ Đại Lải là một hồ nước nhân tạo rộng lớn, được bao quanh bởi rừng thông và núi đồi. Đây là điểm đến lý tưởng để tham gia các hoạt động như chèo thuyền, cắm trại, câu cá hoặc nghỉ dưỡng tại các khu resort ven hồ.', 'Vĩnh Phúc', 'Vĩnh Phúc', 'Vĩnh Phúc', 21.3421, 105.7227, 'nature', '["https://wyndham-thanhthuy.com/wp-content/uploads/2024/09/ho-dai-lai-10.jpg"]', 4.3, 811, '07:00', '17:00', 0, '["citywalk","waterfall","hiking","nature"]');
INSERT INTO `destinations` VALUES (228, 'Làng gốm Hương Canh', 'Làng gốm Hương Canh là một làng nghề truyền thống nổi tiếng với các sản phẩm gốm thủ công tinh xảo, đặc biệt là các sản phẩm gốm gia dụng và nghệ thuật. Du khách có thể tham quan và trải nghiệm làm gốm tại đây.', 'Vĩnh Phúc', 'Vĩnh Phúc', 'Vĩnh Phúc', 21.335898, 105.6046, 'culture', '["https://i.ytimg.com/vi/3XC7fPzfKa8/maxresdefault.jpg"]', 4.1, 253, '07:00', '17:00', 0, '["culture","shopping","hiking","citywalk"]');
INSERT INTO `destinations` VALUES (229, 'Khu du lịch FLC Vĩnh Thịnh', 'FLC Vĩnh Thịnh là khu nghỉ dưỡng cao cấp với không gian sang trọng, tiện nghi. Nơi đây có các dịch vụ đa dạng như bể bơi, spa, sân golf, và nhà hàng, phù hợp cho những chuyến nghỉ dưỡng cùng gia đình.', 'Vĩnh Phúc', 'Vĩnh Phúc', 'Vĩnh Phúc', 21.284816, 105.62746, 'food', '["https://motogo.vn/wp-content/uploads/2020/04/flc-vinh-phuc-9-min.jpg"]', 4.1, 479, '06:00', '22:00', 0, '["themepark","waterfall","coffee"]');
INSERT INTO `destinations` VALUES (230, 'Khu du lịch sinh thái Đầm Vạc', 'Đầm Vạc là một trong những đầm tự nhiên lớn nhất tại Vĩnh Phúc, có hệ sinh thái đa dạng. Du khách có thể tham gia các hoạt động như chèo thuyền, ngắm cảnh, câu cá, hoặc nghỉ ngơi tại các resort ven đầm.', 'Vĩnh Phúc', 'Vĩnh Phúc', 'Vĩnh Phúc', 21.311878, 105.566014, 'attraction', '["https://postumtravel.vn/wp-content/uploads/2022/06/khu-du-lich-dam-vac-2.jpg"]', 4.2, 840, '07:00', '17:30', 0, '["relax","boat","food","street_food"]');
INSERT INTO `destinations` VALUES (231, 'Ruộng bậc thang Mù Cang Chải', 'bậc thang Mù Cang Chải là kiệt tác thiên nhiên và lao động của đồng bào dân tộc H''Mông, nổi tiếng với vẻ đẹp hùng vĩ, đặc biệt vào mùa lúa chín (tháng 9 - tháng 10). Đây là Di sản Quốc gia và một trong những điểm đến hấp dẫn nhất Việt Nam.', 'Yên Bái', 'Yên Bái', 'Yên Bái', 21.8509, 104.089, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRK66m6GnUSJ7OdjdD2BIgcEkNxillIq3zJeg&s"]', 4.3, 2, '07:00', '17:00', 0, '["shopping","swim","photography"]');
INSERT INTO `destinations` VALUES (232, 'Hồ Thác Bà', 'Hồ Thác Bà là một trong những hồ nước nhân tạo lớn nhất Việt Nam, được bao quanh bởi hàng trăm hòn đảo nhỏ và cảnh quan núi non tuyệt đẹp. Du khách có thể tham gia các hoạt động như chèo thuyền, cắm trại, hoặc khám phá hang động quanh hồ.', 'Yên Bái', 'Yên Bái', 'Yên Bái', 21.75, 105, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT1L7AB6L_cA8vq4sI3Yy17tMYk2yx4jmV_2Q&s"]', 4.5, 798, '00:00', '23:59', 0, '["food","hiking"]');
INSERT INTO `destinations` VALUES (233, 'Suối Giàng', 'Suối Giàng nổi tiếng với những cây chè Shan tuyết cổ thụ hàng trăm năm tuổi và khí hậu mát mẻ quanh năm. Đây là nơi lý tưởng để thưởng trà, tận hưởng không khí trong lành và tìm hiểu văn hóa của đồng bào người Mông.', 'Yên Bái', 'Yên Bái', 'Yên Bái', 21.735466, 104.903109, 'nature', '["https://motogo.vn/wp-content/uploads/2020/02/du-lich-yen-bai-mu-cang-chai-7.jpg"]', 4.3, 762, '07:00', '17:00', 0, '["boat","camping","hiking","citywalk"]');
INSERT INTO `destinations` VALUES (234, 'Bản Lìm Mông', 'Bản Lìm Mông là một ngôi làng nhỏ nằm giữa những ngọn núi và ruộng bậc thang tuyệt đẹp. Đây là nơi du khách có thể trải nghiệm cuộc sống của người H''Mông, tận hưởng sự yên bình và không khí trong lành.', 'Yên Bái', 'Yên Bái', 'Yên Bái', 21.717673, 104.931639, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTSxk3hjozJUo0JtAfDF67UVi5NiofujgEHYw&s"]', 4.7, 846, '07:00', '17:00', 0, '["boat","nightmarket","waterfall"]');
INSERT INTO `destinations` VALUES (235, 'Buôn Đôn', 'Buôn Đôn, nằm tại tỉnh Đắk Lắk, Việt Nam, là một vùng đất nổi tiếng với văn hóa đặc sắc và khung cảnh thiên nhiên hùng vĩ. Đây là vùng đất của người dân tộc Ê-đê và Mnông, nơi bạn có thể khám phá những nét văn hóa độc đáo và các hoạt động thú vị', 'Đắk Lắk', 'Đắk Lắk', 'Đắk Lắk', 12.878, 107.8278, 'culture', '["https://cdn.tgdd.vn/Files/2023/09/28/1549550/du-lich-buon-don-dak-lak-7-dia-diem-khong-the-bo-lo-202309282152153920.jpg"]', 3.6, 612, '07:00', '17:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (236, 'Hồ Lắk', 'Hồ Lắk là một hồ nước lớn tại Việt Nam, nằm ở phía tây bắc tỉnh Lâm Đồng. Hồ này được biết đến với cảnh quan thiên nhiên tuyệt đẹp và đa dạng sinh học phong phú. Hồ Lắk cũng là một điểm đến thu hút du khách với các hoạt động như lặn biển, câu cá, và du thuyền', 'Đắk Lắk', 'Đắk Lắk', 'Đắk Lắk', 12.4141, 108.1704, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTsOvhXUBk60SmnYLmkC5qZ1c-BF0w4VF5Dyw&s"]', 3.4, 57, '00:00', '23:59', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (237, 'Thác Dray Nur', 'Thác Dray Nur, nằm ở tỉnh Đắk Lắk, là một trong những thác nước đẹp và hùng vĩ nhất của Tây Nguyên. Thác này nằm bên dòng sông Sêrêpôk, nổi tiếng với vẻ đẹp hoang sơ và huyền bí', 'Đắk Lắk', 'Đắk Lắk', 'Đắk Lắk', 12.5345, 107.8899, 'nature', '["https://images.baodantoc.vn/uploads/2021/Th%C3%A1ng_10/Ng%C3%A0y_14/NGN%C3%82/th%C3%A1c%20Dray%20Nur/41-1634140188-dray-nur.jpg"]', 3.9, 228, '07:00', '17:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (238, 'Bảo tàng cà phê Thế giới', 'Bảo tàng Thế giới Cà phê, tọa lạc tại Buôn Ma Thuột, Đắk Lắk, là một điểm đến hấp dẫn cho những ai yêu thích cà phê và muốn tìm hiểu về văn hóa cà phê toàn cầu', 'Đắk Lắk', 'Đắk Lắk', 'Đắk Lắk', 12.6903, 108.0372, 'historical', '["https://thaiantravel.com/wp-content/uploads/2024/06/bao-tang-the-gioi-ca-phe-o-tay-nguyen-1-jpg.webp"]', 3.7, 733, '07:00', '17:00', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (239, 'Khu du lịch Ko Tam', 'Khu du lịch Ko Tam, tọa lạc tại Buôn Ma Thuột, Đắk Lắk, là một điểm đến sinh thái và văn hóa nổi bật của Tây Nguyên. Với diện tích khoảng 13 hecta, Ko Tam mang đến cho du khách một không gian thiên nhiên hoang sơ và yên bình, cùng với những nét văn hóa đặc sắc của người dân tộc Ê-đê', 'Đắk Lắk', 'Đắk Lắk', 'Đắk Lắk', 12.69694, 108.230423, 'culture', '["https://vcdn1-dulich.vnecdn.net/2023/09/18/thac-lieng-nung-ha-the-bao-169-4064-1297-1695029127.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PEGSVxss36taUtg2gGqjxA"]', 3, 965, '07:00', '17:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (240, 'Công viên địa chất Đắk Nông', 'Công viên Địa chất Đắk Nông nổi tiếng với hệ thống hang động núi lửa độc đáo, bao gồm gần 50 hang động với tổng chiều dài hơn 10.000 mét. Công viên Địa chất Đắk Nông không chỉ là nơi bảo tồn các giá trị địa chất, mà còn là nơi lưu giữ và giới thiệu văn hóa của các dân tộc bản địa như người Mạ, người Mnông và người Ê-đê', 'Đắk Nông', 'Đắk Nông', 'Đắk Nông', 12.024659, 107.685965, 'theme_park', '["https://vcdn1-dulich.vnecdn.net/2023/09/18/thac-lieng-nung-ha-the-bao-169-4064-1297-1695029127.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=PEGSVxss36taUtg2gGqjxA"]', 4.5, 1, '08:00', '18:00', 200000, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (241, 'Thác Dray Sap', 'Thác Dray Sap, còn được gọi là Thác Khói, là một trong những thác nước đẹp và hùng vĩ nhất của Tây Nguyên', 'Đắk Nông', 'Đắk Nông', 'Đắk Nông', 12.5404, 107.893, 'nature', '["https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/10/dray-sap-1.jpg"]', 3.4, 965, '07:00', '17:00', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (242, 'Hang động Chư Bluk', 'Hang động Chư Bluk, nằm ở huyện Krông Nô, tỉnh Đắk Nông, là hệ thống hang động núi lửa dài nhất Đông Nam Á. Hang động Chư Bluk nổi bật với vẻ đẹp hoang sơ và kỳ bí, với những cấu trúc đá bazan độc đáo và hệ sinh thái phong phú. Đây là điểm đến lý tưởng cho những ai yêu thích khám phá và mạo hiểm, bởi việc tiếp cận hang động không hề dễ dàng và đòi hỏi sự hướng dẫn của người dân địa phương', 'Đắk Nông', 'Đắk Nông', 'Đắk Nông', 11.999598, 107.658022, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTnfpJMgpfKMIvaekKmSaiDLqoAG1EkhGtEJg&s"]', 4.8, 602, '07:00', '17:00', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (243, 'Hồ Ea Snô', 'Hồ Ea Snô được bao quanh bởi hệ sinh thái thực vật đa dạng và phong phú, là nơi sinh sống của nhiều cộng đồng dân tộc bản địa. Khung cảnh nơi đây mang lại cảm giác bình yên và thư thá', 'Đắk Nông', 'Đắk Nông', 'Đắk Nông', 12.034297, 107.715503, 'nature', '["https://nqs.1cdn.vn/2023/06/11/dautu.kinhtechungkhoan.vn-stores-news_dataimages-2023-062023-11-11-_t1-222620230611115748.jpg"]', 4.6, 181, '07:00', '17:00', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (244, 'Khu bảo tồn thiên nhiên Nâm Nung', 'Khu bảo tồn nằm ở tỉnh Đắk Nông, nổi tiếng với hệ sinh thái đa dạng gồm rừng nguyên sinh, thác nước hùng vĩ và nhiều loài động thực vật quý hiếm. Đây là địa điểm lý tưởng cho các hoạt động khám phá thiên nhiên, trekking, và nghiên cứu sinh thái.', 'Đắk Nông', 'Đắk Nông', 'Đắk Nông', 11.959262, 107.693055, 'nature', '["https://danviet.mediacdn.vn/296231569849192448/2022/7/7/d7d72db1fc3e3f60662f-16571735477191741026026.jpg"]', 4.3, 555, '07:00', '17:00', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (245, 'Đồi A1', 'Đồi A1 là một trong những di tích lịch sử quan trọng trong chiến dịch Điện Biên Phủ, nơi từng diễn ra các trận đánh khốc liệt. Hiện nay, nơi đây trở thành điểm tham quan với hầm chiến đấu, hệ thống giao thông hào và bảo tồn nhiều hiện vật lịch sử.', 'Điện Biên', 'Điện Biên', 'Điện Biên', 21.3855, 103.0169, 'historical', '["https://dienbientv.vn/dataimages/201907/original/images2790806_29.jpg"]', 3.7, 162, '07:00', '17:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (246, 'Hầm De Castries', 'Đây là nơi ở và chỉ huy của tướng De Castries trong chiến dịch Điện Biên Phủ. Hầm được xây dựng kiên cố và hiện nay là di tích lịch sử được bảo tồn để tái hiện lại chiến trường năm xưa.', 'Điện Biên', 'Điện Biên', 'Điện Biên', 21.384, 103.018, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSh6mulULwY4KND80JkIMOAeIg2wkGdNHAjZw&s"]', 3.2, 1, '07:00', '17:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (247, 'Bảo tàng chiến thắng Điện Biên Phủ', 'Bảo tàng lưu giữ các hiện vật, tư liệu và hình ảnh về chiến dịch Điện Biên Phủ, tái hiện lịch sử hào hùng của dân tộc Việt Nam. Đây là điểm đến không thể bỏ qua khi ghé thăm Điện Biên.', 'Điện Biên', 'Điện Biên', 'Điện Biên', 21.3862, 103.0166, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTum8lds95DiG7GYG-gW2VKxz0lUn0sJUqiGw&s"]', 4.8, 132, '07:00', '17:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (248, 'Cánh đồng Mường Thanh', 'Cánh đồng lúa lớn nhất vùng Tây Bắc, nổi tiếng với vẻ đẹp thơ mộng và vai trò quan trọng trong lịch sử chiến dịch Điện Biên Phủ. Cảnh quan ở đây thay đổi theo mùa vụ, thu hút nhiều du khách đến chiêm ngưỡng.', 'Điện Biên', 'Điện Biên', 'Điện Biên', 21.412797, 103.026305, 'historical', '["https://dulichkhatvongviet.com/wp-content/uploads/2022/02/Dep-ngo-ngang-truoc-ve-dep-mua-vang-cua-canh-dong-Muong-Thanh.jpg"]', 3.7, 653, '07:00', '17:00', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (249, 'Tượng đài chiến thắng Điện Biên Phủ', 'Tượng đài nằm trên đồi D1, là biểu tượng của chiến thắng lịch sử Điện Biên Phủ. Đây là nơi tôn vinh sự hy sinh và chiến công của các chiến sĩ Việt Nam, đồng thời cũng là điểm ngắm toàn cảnh thành phố Điện Biên.', 'Điện Biên', 'Điện Biên', 'Điện Biên', 21.3866, 103.013, 'historical', '["https://bizweb.dktcdn.net/100/006/093/files/tuong-dai-chien-thang-dien-bien-phu-1.jpg?v=1709521625245"]', 4.1, 72, '07:00', '17:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (250, 'Vườn quốc gia Cát Tiên', 'Một trong những vườn quốc gia nổi tiếng nhất Việt Nam, nằm ở tỉnh Đồng Nai. Nơi đây sở hữu hệ sinh thái phong phú với nhiều loài động thực vật quý hiếm, cùng các hoạt động như khám phá rừng, ngắm chim và dã ngoại.', 'Đồng Nai', 'Đồng Nai', 'Đồng Nai', 11.4227, 107.4261, 'historical', '["https://cattiennationalpark.com.vn/wp-content/uploads/2023/03/word-image-6772-3-768x512.jpeg"]', 4.9, 594, '07:00', '17:00', 60000, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (251, 'Khu du lịch Bửu Long', 'Được ví như “Vịnh Hạ Long thu nhỏ” ở Đồng Nai, Bửu Long nổi bật với hồ nước trong xanh, núi đá và cảnh quan thơ mộng. Đây là nơi lý tưởng cho các hoạt động dã ngoại, cắm trại và chụp ảnh.', 'Đồng Nai', 'Đồng Nai', 'Đồng Nai', 10.9635, 106.7954, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTRUQFhtdPrAb32sIE09O6TgymIvvjoRn5JSA&s"]', 3.3, 579, '00:00', '23:59', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (252, 'Hồ Trị An', 'Hồ Trị An với trên 70 đảo lớn, nhỏ và nhiều đảo trong số này có cư dân sinh sống, cộng thêm vài hòn đảo có diện tích lớn được khai thác du lịch gần chục năm trở lại đây đã trở thành điểm nhấn của sông nước Trị An', 'Đồng Nai', 'Đồng Nai', 'Đồng Nai', 11.105, 107.037, 'beach', '["https://mia.vn/media/uploads/blog-du-lich/camping-ho-tri-an-4-1693238728.jpg"]', 4.9, 664, '00:00', '23:59', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (253, 'Đảo Ó', 'Một hòn đảo nằm giữa lòng hồ Trị An, sở hữu không gian xanh mát và trong lành. Đảo Ó là điểm đến hấp dẫn cho các hoạt động dã ngoại, cắm trại, và thưởng ngoạn thiên nhiên.', 'Đồng Nai', 'Đồng Nai', 'Đồng Nai', 10.970947, 106.836259, 'beach', '["https://zoomtravel.vn/upload/news/vien-ngoc-giua-long-ho-tri-an-thien-nhien-hoang-so-ky-vi12230.jpg"]', 3.5, 997, '00:00', '23:59', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (254, 'Thác Giang Điền', 'Một thác nước đẹp ở Đồng Nai, được bao quanh bởi rừng cây xanh mát. Thác Giang Điền là địa điểm du lịch sinh thái, hấp dẫn cho các hoạt động nghỉ dưỡng, picnic và chụp ảnh kỷ niệm.', 'Đồng Nai', 'Đồng Nai', 'Đồng Nai', 10.933, 106.997, 'nature', '["https://mia.vn/media/uploads/blog-du-lich/thac-giang-dien-va-nhung-trai-nghiem-thu-vi-co-mot-khong-hai-03-1689266277.jpg"]', 3, 498, '07:00', '17:00', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (255, 'Vườn quốc gia Tràm Chim', 'Vườn quốc gia ở Đồng Tháp, nơi bảo tồn hệ sinh thái đất ngập nước đặc trưng Đồng bằng sông Cửu Long. Tràm Chim là nhà của nhiều loài chim quý hiếm, đặc biệt là sếu đầu đỏ.', 'Đồng Tháp', 'Đồng Tháp', 'Đồng Tháp', 10.715, 105.491, 'nature', '["https://tainguyenvamoitruong.vn/images/news/lg-danh-gia-tac-dong-cua-nguoi-dan-den-khu-vuc-vuon-quoc-gia-tram-chim-tai-xa-phu-tho-phu-duc-huyen-tam-nong-tinh-dong-thap_566.jpg"]', 4.6, 381, '07:00', '17:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (256, 'Làng hoa Sa Đéc', 'Làng nghề truyền thống nổi tiếng ở Đồng Tháp, nơi trồng hàng trăm loài hoa đẹp và quý. Làng hoa thu hút du khách với những vườn hoa rực rỡ quanh năm.', 'Đồng Tháp', 'Đồng Tháp', 'Đồng Tháp', 10.304, 105.772, 'historical', '["https://scontent.iocvnpt.com/resources/portal/Images/DTP/dtblieu/lang_hoa/48bf9d85d2d3118d48c2_826106342.jpeg"]', 4.8, 554, '07:00', '17:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (257, 'Khu di tích Xẻo Quýt', 'Một khu di tích lịch sử kết hợp du lịch sinh thái tại Đồng Tháp, nơi tái hiện các căn cứ cách mạng trong rừng tràm thời kháng chiến.', 'Đồng Tháp', 'Đồng Tháp', 'Đồng Tháp', 10.681, 105.736, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTNFW3oOOp10fGV9fAYtic3l1Y4dmLSb7Q3zg&s"]', 3.5, 869, '07:00', '17:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (258, 'Lăng cụ Nguyễn Sinh Sắc', 'Nơi an nghỉ của cụ Nguyễn Sinh Sắc, thân sinh Chủ tịch Hồ Chí Minh. Lăng được thiết kế hài hòa giữa kiến trúc và cảnh quan thiên nhiên.', 'Đồng Tháp', 'Đồng Tháp', 'Đồng Tháp', 10.517721, 105.650085, 'historical', '["https://scontent.iocvnpt.com/resources/portal/Images/DTP/superadminportal.dtp/trangchu/portal/luutru/diadiem/ditichnguyensinhsac/h1.jpg_636758375125902652.jpg"]', 3.4, 849, '07:00', '17:00', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (259, 'Chợ Cao Lãnh', 'Một khu chợ sầm uất tại thành phố Cao Lãnh, nơi du khách có thể khám phá văn hóa ẩm thực và đời sống người dân địa phương.', 'Đồng Tháp', 'Đồng Tháp', 'Đồng Tháp', 10.502989, 105.738365, 'food', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcREw0kvfKqWUVy7gogbII8hIDj_ivcyzfhDiQ&s"]', 4.7, 665, '06:00', '22:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (260, 'Biển Hồ', 'Một khu chợ sầm uất tại thành phố Cao Lãnh, nơi du khách có thể khám phá văn hóa ẩm thực và đời sống người dân địa phương.', 'Gia Lai', 'Gia Lai', 'Gia Lai', 14.0415, 108.0114, 'food', '["https://sakos.vn/wp-content/uploads/2024/08/1-18.jpg"]', 4.3, 68, '06:00', '22:00', 0, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (261, 'Thác Phú Cường', 'Một thác nước đẹp tại Gia Lai, nằm giữa rừng nguyên sinh. Thác nổi bật với dòng nước trắng xóa, đổ từ độ cao hơn 45m.', 'Gia Lai', 'Gia Lai', 'Gia Lai', 13.731, 108.256, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT_VHJsbvkvT0mm43ZwE4YjRaLmOPaDjxeXKQ&s"]', 4.9, 747, '07:00', '17:00', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (262, 'Chùa Minh Thành', 'Ngôi chùa nổi tiếng ở Gia Lai, được xây dựng theo phong cách Phật giáo Nhật Bản, với kiến trúc độc đáo và không gian thanh tịnh.', 'Gia Lai', 'Gia Lai', 'Gia Lai', 13.9795, 108.016, 'religious', '["https://datviettour.com.vn/uploads/images/tin-tuc-SEO/tay-nguyen/danh-thang/chua-minh-thanh-pleiku.jpg"]', 4, 223, '07:00', '18:00', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (263, 'Quảng trường Đại Đoàn Kết', 'Quảng trường lớn nhất Tây Nguyên, nằm tại Pleiku, Gia Lai. Đây là nơi tổ chức các sự kiện lớn và cũng là biểu tượng của đoàn kết dân tộc.', 'Gia Lai', 'Gia Lai', 'Gia Lai', 13.9838, 108.003, 'attraction', '["https://mia.vn/media/uploads/blog-du-lich/quang-truong-dai-doan-ket-noi-ket-tinh-tu-tuong-dan-toc-1659087815.jpg"]', 4.7, 377, '07:00', '17:30', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (264, 'Đồi chè Bàu Cạn', 'Đồi chè Bàu Cạn ở Gia Lai là một trong những đồi chè lâu đời nhất Việt Nam, nổi bật với những luống chè xanh mướt trải dài, mang vẻ đẹp yên bình. Đây là điểm đến lý tưởng để thư giãn và chụp ảnh giữa không gian thiên nhiên tươi mát.', 'Gia Lai', 'Gia Lai', 'Gia Lai', 14.009818, 108.028597, 'nature', '["https://mia.vn/media/uploads/blog-du-lich/ghe-tham-doi-che-bau-can-voi-sac-xanh-cuc-quyen-ru-02-1659459923.jpg"]', 3.7, 84, '07:00', '17:00', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (265, 'Cột cờ Lũng Cú', 'Cột cờ Lũng Cú, nằm ở cực Bắc Việt Nam (Hà Giang), là biểu tượng thiêng liêng của chủ quyền quốc gia. Du khách chinh phục gần 800 bậc thang để chiêm ngưỡng lá cờ đỏ sao vàng tung bay trên đỉnh núi hùng vĩ.', 'Hà Giang', 'Hà Giang', 'Hà Giang', 23.3637, 105.3147, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSigfgZFV4EvIXqI5SCa9MfMv9bGaePC9_0VQ&s"]', 3.9, 554, '07:00', '17:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (266, 'Đèo Mã Pí Lèng', 'Đèo Mã Pí Lèng là cung đường hùng vĩ tại Hà Giang, với sông Nho Quế xanh ngọc chảy uốn lượn phía dưới. Đây là điểm thu hút phượt thủ và du khách yêu vẻ đẹp thiên nhiên hoang sơ.', 'Hà Giang', 'Hà Giang', 'Hà Giang', 23.2606, 105.4109, 'historical', '["https://owa.bestprice.vn/images/destinations/uploads/deo-ma-pi-leng-6001155be6540.jpg"]', 4, 974, '07:00', '17:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (267, 'Phố cổ Đồng Văn', 'Phố cổ Đồng Văn (Hà Giang) lưu giữ nét kiến trúc cổ kính với những ngôi nhà tường đất, mái ngói âm dương. Phiên chợ cuối tuần nhộn nhịp là điểm nhấn văn hóa hấp dẫn.', 'Hà Giang', 'Hà Giang', 'Hà Giang', 23.278, 105.36, 'food', '["https://tuyengiao.hagiang.gov.vn/upload/64711/fck/leminhtien.btgtu/2022_06_16_23_23_014.png"]', 5, 250, '06:00', '22:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (268, 'Hẻm Tu Sản', 'Hẻm Tu Sản, nơi sâu nhất Đông Nam Á, nổi bật với vách đá cao 800m và dòng sông Nho Quế xanh biếc. Du khách có thể chèo thuyền khám phá khung cảnh kỳ vĩ này.', 'Hà Giang', 'Hà Giang', 'Hà Giang', 23.2538, 105.4117, 'attraction', '["https://images.baodantoc.vn/uploads/2022/Th%C3%A1ng%201/Ng%C3%A0y%207/NG%C3%82N/Tu%20S%E1%BA%A3n/kham-pha-ve-dep-hem-tu-san-hem-vuc-sau-nhat-tai-dong-nam-a-o-ha-giang3-1639281377835787560145.jpg"]', 4.5, 381, '07:00', '17:30', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (269, 'Dinh Vua Mèo', 'Dinh Vua Mèo (Hà Giang) là dinh thự cổ của dòng họ Vương, với kiến trúc kết hợp độc đáo giữa Trung Hoa, Pháp và văn hóa dân tộc H''Mông, thu hút nhiều du khách tham quan.', 'Hà Giang', 'Hà Giang', 'Hà Giang', 23.2566, 105.251, 'historical', '["https://i2.ex-cdn.com/crystalbay.com/files/content/2024/09/25/dinh-thu-vua-meo-1-1430.jpg"]', 4.8, 1, '07:00', '17:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (270, 'Chùa Tam Chúc', 'Chùa Tam Chúc (Hà Nam) là một trong những quần thể chùa lớn nhất Việt Nam, nổi bật với kiến trúc hoành tráng và cảnh quan thiên nhiên tươi đẹp. Được bao quanh bởi những dãy núi, hồ nước trong xanh, đây là nơi thu hút tín đồ Phật giáo và du khách tham quan.', 'Hà Nam', 'Hà Nam', 'Hà Nam', 20.5433, 105.9247, 'religious', '["https://www.kynghidongduong.vn/images/product/img2/du-lich-chua-tam-chuc-kynghidongduong-004.jpg"]', 4, 93, '06:00', '18:00', 0, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (271, 'Đền Trần Thương', 'Đền Trần Thương (Hà Nam) thờ các vị vua Trần, nổi bật với kiến trúc cổ kính và không gian thanh tịnh. Đền là điểm đến văn hóa, tâm linh, thu hút du khách vào mùa lễ hội.', 'Hà Nam', 'Hà Nam', 'Hà Nam', 20.4226, 106.161, 'religious', '["https://mia.vn/media/uploads/blog-du-lich/den-tran-thuong-7-1696133302.jpg"]', 4.9, 854, '07:00', '18:00', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (272, 'Hang Luồn', 'Hang Luồn, nằm trong khu di tích Hạ Long, Quảng Ninh, nổi tiếng với hệ thống hang động kỳ vĩ. Du khách có thể chèo thuyền vào hang, khám phá vẻ đẹp hoang sơ của thiên nhiên.', 'Hà Nam', 'Hà Nam', 'Hà Nam', 20.600921, 105.964491, 'historical', '["https://www.dulichhalong.net/wp-content/uploads/Hang-Luon-Halong.jpg"]', 4.1, 630, '07:00', '17:00', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (273, 'Đền Lảnh Giang', 'Đền Lảnh Giang (Hưng Yên) là di tích lịch sử thờ các bậc vua hùng, mang đậm giá trị văn hóa và lịch sử. Đây là một điểm du lịch tâm linh nổi bật tại miền Bắc.', 'Hà Nam', 'Hà Nam', 'Hà Nam', 20.537178, 105.901663, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRC0tZbj_KAypbee0hvzuXUKlPNYZrhTvMsCQ&s"]', 4.2, 1, '07:00', '18:00', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (274, 'Làng Vũ Đại', 'Làng Vũ Đại (Hà Nam) nổi tiếng nhờ sự gắn kết với tác phẩm "Chí Phèo" của nhà văn Nam Cao. Nơi đây có những ngôi nhà cổ, là điểm du lịch văn hóa, nơi lưu giữ nét đẹp văn hóa truyền thống.', 'Hà Nam', 'Hà Nam', 'Hà Nam', 20.597785, 105.918425, 'culture', '["https://baogiaothong.mediacdn.vn/upload/images/2019-3/article_img/2019-09-12/ngo-i-nha-ba-kie-n-gio-tro-tha-nh-mo-t-die-m-tham-quan-mie-n-phi-cho-du-kha-ch--1568293960-width914height486.jpg"]', 3.8, 2, '07:00', '17:00', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (275, 'Lăng Chủ tịch Hồ Chí Minh', 'Lăng Chủ tịch Hồ Chí Minh (Hà Nội) là nơi lưu giữ thi hài của Chủ tịch Hồ Chí Minh, trở thành biểu tượng của lòng tôn kính và biết ơn của nhân dân Việt Nam.', 'Hà Nội', 'Hà Nội', 'Hà Nội', 21.0367, 105.8347, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRMHx0pkR_hUf4DaJq8ywbEqYONg2J014vbnw&s"]', 4.2, 93, '07:30', '10:30', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (276, 'Hồ Gươm', 'Hồ Gươm (Hà Nội) là trung tâm của thủ đô, nổi bật với Tháp Rùa và cầu Thê Húc. Đây là điểm du lịch hấp dẫn, nơi người dân thư giãn và là biểu tượng của Hà Nội.', 'Hà Nội', 'Hà Nội', 'Hà Nội', 21.0287, 105.8524, 'historical', '["https://images.vietnamtourism.gov.vn/vn/images/2021/ho_guom.jpg"]', 3.2, 992, '07:00', '17:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (277, 'Văn Miếu - Quốc Tử Giám', 'Văn Miếu - Quốc Tử Giám (Hà Nội) là một di tích lịch sử và văn hóa, nơi thờ Khổng Tử và là trường đại học đầu tiên của Việt Nam. Đây là điểm tham quan giáo dục và văn hóa.', 'Hà Nội', 'Hà Nội', 'Hà Nội', 21.028, 105.8355, 'religious', '["https://honglam.vn/pic/general/images/van-mieu-quoc-tu-giam%20(5).png"]', 3.1, 625, '08:00', '17:00', 30000, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (278, 'Hoàng thành Thăng Long', 'Hoàng Thành Thăng Long (Hà Nội) là di tích lịch sử quan trọng của Việt Nam, từng là trung tâm quyền lực của nhiều triều đại. Di tích này mang đậm dấu ấn lịch sử và văn hóa dân tộc.', 'Hà Nội', 'Hà Nội', 'Hà Nội', 21.0355, 105.8403, 'historical', '["https://hoangthanhthanglong.vn/wp-content/uploads/2023/05/hoangthanh.jpg"]', 3.6, 872, '08:00', '17:00', 30000, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (279, 'Cầu Long Biên', 'Cầu Long Biên (Hà Nội) là một trong những cây cầu lâu đời nhất, mang đậm giá trị lịch sử. Cầu nối liền hai bờ sông Hồng và là biểu tượng của thủ đô.', 'Hà Nội', 'Hà Nội', 'Hà Nội', 21.043, 105.858, 'historical', '["https://i2.ex-cdn.com/crystalbay.com/files/content/2024/09/12/cau-long-bien-1-1709.jpg"]', 3.5, 681, '07:00', '17:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (280, 'Ngã ba Đồng Lộc', 'Ngã ba Đồng Lộc (Hà Tĩnh) là di tích lịch sử nổi tiếng gắn liền với cuộc kháng chiến chống Mỹ. Nơi đây là nơi tưởng niệm các liệt sĩ hy sinh trong chiến tranh.', 'Hà Tĩnh', 'Hà Tĩnh', 'Hà Tĩnh', 18.4829, 105.632, 'historical', '["https://lh5.googleusercontent.com/proxy/sF7ugItIUxhPD4gRthgCfsONGinLrN4hEqo_HzazT8C3WqdNtM-xAkxSX-huljbHsrCQLUpdXEgl5zs6Ne7fTaq__2Y"]', 4.4, 512, '07:00', '17:00', 0, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (281, 'Chùa Hương Tích', 'Ngã ba Đồng Lộc (Hà Tĩnh) là di tích lịch sử nổi tiếng gắn liền với cuộc kháng chiến chống Mỹ. Nơi đây là nơi tưởng niệm các liệt sĩ hy sinh trong chiến tranh.', 'Hà Tĩnh', 'Hà Tĩnh', 'Hà Tĩnh', 18.43, 105.712, 'religious', '["https://static.kinhtedothi.vn/images/upload/2021/12/20/7a462a22-c4d4-492f-b92a-c83c57c2e93d.jpg"]', 3.9, 974, '07:00', '18:00', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (282, 'Biển Thiên Cầm', 'Biển Thiên Cầm (Hà Tĩnh) là bãi biển xinh đẹp với bãi cát dài và nước biển trong xanh, nơi du khách có thể thư giãn và tham gia các hoạt động thể thao biển.', 'Hà Tĩnh', 'Hà Tĩnh', 'Hà Tĩnh', 18.242, 106.093, 'beach', '["https://thiencam.net/wp-content/uploads/2017/04/thien-cam-ha-tinh.jpg"]', 3.2, 766, '00:00', '23:59', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (283, 'Khu di tích Nguyễn Du', 'Khu di tích Nguyễn Du (Hà Tĩnh) là nơi tưởng niệm đại thi hào Nguyễn Du, tác giả của "Truyện Kiều". Di tích này giữ gìn những giá trị văn hóa, lịch sử về cuộc đời và sự nghiệp của ông.', 'Hà Tĩnh', 'Hà Tĩnh', 'Hà Tĩnh', 18.4567, 105.713, 'historical', '["https://bizweb.dktcdn.net/100/467/540/files/5e51f1b2-2e3d-495d-ba66-b2fc90acdf3f-c2174aa5-b9f4-484f-9089-1e386f3d8ff1.jpg?v=1695609583388"]', 4.9, 372, '07:00', '17:00', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (284, 'Đèo Ngang', 'Đèo Ngang (Quảng Bình) là một trong những con đèo đẹp nhất Việt Nam, nối liền hai tỉnh Quảng Bình và Hà Tĩnh. Đèo có cảnh quan hùng vĩ và thơ mộng.', 'Hà Tĩnh', 'Hà Tĩnh', 'Hà Tĩnh', 17.954, 106.466, 'attraction', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSYlUKMe1H2ET_dO5xzAeo6GyQ6R07Ci3huow&s"]', 4.3, 315, '07:00', '17:30', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (285, 'Đảo Cò Chi Lăng Nam', 'Đảo Cò Chi Lăng Nam (Hải Dương) là một khu vực bảo tồn thiên nhiên nổi bật với hàng nghìn con cò sinh sống. Đây là địa điểm du lịch sinh thái lý tưởng, với không gian yên bình và cảnh quan tuyệt đẹp.', 'Hải Dương', 'Hải Dương', 'Hải Dương', 20.959765, 106.34648, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRpzhFtGutS_W02Fr-0hiSq89Y7JzA_vKdnSA&s"]', 3.3, 169, '00:00', '23:59', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (286, 'Chùa Côn Sơn', 'Chùa Côn Sơn (Hải Dương) là di tích lịch sử và văn hóa, nổi bật với kiến trúc cổ kính và không gian thanh tịnh. Nơi đây là một trong những địa điểm du lịch tâm linh nổi tiếng ở miền Bắc.', 'Hải Dương', 'Hải Dương', 'Hải Dương', 21.1393, 106.3926, 'religious', '["https://consonkiepbac.org.vn/wp-content/uploads/2021/03/Cuu-pham-3.jpg"]', 3.5, 978, '07:00', '18:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (287, 'Làng rối nước Thanh Hải', 'Làng rối nước Thanh Hải (Hải Dương) là nơi bảo tồn và phát triển nghệ thuật rối nước truyền thống. Du khách có thể thưởng thức những màn rối đặc sắc trong không gian văn hóa dân gian đậm đà.', 'Hải Dương', 'Hải Dương', 'Hải Dương', 20.981398, 106.28898, 'culture', '["https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/06_2021/lang-roi-nuoc-thanh-hai-sa.png"]', 4.1, 910, '07:00', '17:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (288, 'Đền Kiếp Bạc', 'Đền Kiếp Bạc (Hải Dương) là nơi thờ Hưng Đạo Đại Vương Trần Quốc Tuấn, người có công lớn trong chiến tranh chống Nguyên. Đền mang đậm giá trị lịch sử và văn hóa.', 'Hải Dương', 'Hải Dương', 'Hải Dương', 21.143, 106.389, 'religious', '["https://vietsensetravel.com/view/at_den-kiep-bac_910af4a7a9046696946822e976e0a962.jpg"]', 4, 1, '07:00', '18:00', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (289, 'Chợ Đông Ngô Quyền', 'Chợ Đông Ngô Quyền (Hải Phòng) là chợ truyền thống nổi tiếng với đa dạng mặt hàng và không khí tấp nập. Chợ là nơi giao thương của người dân địa phương và du khách.', 'Hải Dương', 'Hải Dương', 'Hải Dương', 20.928379, 106.295589, 'food', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR5VsYHUiMpVj0SqNQ-3n5vB7orjjCW2v9jzw&s"]', 3.5, 451, '06:00', '22:00', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (290, 'Đồ Sơn', 'Đồ Sơn (Hải Phòng) là một bãi biển đẹp nổi tiếng với những dãy núi và biển xanh. Đây là khu du lịch biển với các hoạt động thể thao nước và thư giãn dưới ánh nắng.', 'Hải Phòng', 'Hải Phòng', 'Hải Phòng', 20.7137, 106.789, 'beach', '["https://vietrapro.com/wp-content/uploads/2017/05/bai-bien-do-son-hai-phong.jpg"]', 3.5, 153, '00:00', '23:59', 0, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (291, 'Cát Bà', 'Cát Bà (Hải Phòng) là hòn đảo nổi tiếng với bãi biển tuyệt đẹp và hệ sinh thái đa dạng. Nơi đây là một điểm đến lý tưởng cho những ai yêu thích du lịch sinh thái và biển.', 'Hải Phòng', 'Hải Phòng', 'Hải Phòng', 20.7278, 107.0482, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR3GEramqChIIWX08m0x2Cq_5N26odngXetIA&s"]', 4.8, 326, '00:00', '23:59', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (292, 'Bến Nghiêng - Bến K15', 'Bến Nghiêng (Bến K15) (Quảng Ninh) là một bến cảng nổi tiếng, gắn liền với lịch sử chiến tranh. Đây là một trong những điểm di tích lịch sử quan trọng của miền Bắc.', 'Hải Phòng', 'Hải Phòng', 'Hải Phòng', 20.7113, 106.792, 'historical', '["https://image.vietgoing.com/editor/image_czc1638431389.jpg"]', 4.1, 907, '07:00', '17:00', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (293, 'Hải đăng Hòn Dấu', 'Hải đăng Hòn Dấu (Hải Phòng) là ngọn hải đăng cổ kính, nằm trên đảo Hòn Dấu. Đây là một trong những ngọn hải đăng quan trọng ở khu vực vịnh Bắc Bộ.', 'Hải Phòng', 'Hải Phòng', 'Hải Phòng', 20.6698, 106.815, 'beach', '["https://ticotravel.com.vn/wp-content/uploads/2022/05/Hai-dang-Hon-Dau-2.jpg"]', 4, 348, '00:00', '23:59', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (294, 'Cầu Hoàng Văn Thụ', 'Cầu Hoàng Văn Thụ (Hải Phòng) là một cây cầu huyết mạch nối liền các khu vực trong thành phố. Cầu nổi bật với kiến trúc hiện đại và là điểm đến tham quan chính của du khách.', 'Hải Phòng', 'Hải Phòng', 'Hải Phòng', 20.8688, 106.6786, 'beach', '["https://imagev3.dantocmiennui.vn/w1000/Uploaded/2024/ngotzz/2022_08_25/cauhoangvanthu2.jpeg"]', 3.3, 738, '00:00', '23:59', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (295, 'Khu du lịch Lung Ngọc Hoàng', 'Khu du lịch Lung Ngọc Hoàng (Hậu Giang) là khu bảo tồn thiên nhiên nổi bật với hệ sinh thái rừng ngập mặn. Đây là điểm đến lý tưởng cho những ai yêu thích du lịch sinh thái và nghiên cứu động thực vật.', 'Hậu Giang', 'Hậu Giang', 'Hậu Giang', 9.799268, 105.467472, 'nature', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRCuDRxQuW4UyoIJKAcItE_ahWHE3_moYpOXg&s"]', 5, 802, '07:00', '17:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (296, 'Chợ nổi Ngã Bảy', 'Chợ nổi Ngã Bảy (Hậu Giang) là một trong những chợ nổi nổi tiếng ở miền Tây. Du khách có thể trải nghiệm việc mua bán trên sông và khám phá nền văn hóa chợ nổi đặc sắc.', 'Hậu Giang', 'Hậu Giang', 'Hậu Giang', 9.77174, 105.486779, 'food', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTWb2p0D3meLtBculBebw-4Pea5g8O-zyvo1g&s"]', 3, 837, '06:00', '22:00', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (297, 'Công viên giải trí Vinpearl Hậu Giang', 'Công viên giải trí Vinpearl Hậu Giang là khu vui chơi giải trí hiện đại, với nhiều trò chơi hấp dẫn cho cả gia đình. Đây là điểm đến lý tưởng cho du khách tìm kiếm sự giải trí và thư giãn.', 'Hậu Giang', 'Hậu Giang', 'Hậu Giang', 9.782111, 105.443206, 'theme_park', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTKcf2MdvR1tzFaSudJbTNbCmNy5Jxo-qQoIw&s"]', 4.3, 576, '08:00', '18:00', 200000, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (298, 'Sông Cái Lớn', 'Sông Cái Lớn (Cà Mau) là con sông dài, chảy qua các tỉnh miền Tây. Nơi đây có hệ sinh thái phong phú và là điểm du lịch sinh thái nổi bật của vùng đồng bằng sông Cửu Long.', 'Hậu Giang', 'Hậu Giang', 'Hậu Giang', 9.7455, 105.470141, 'attraction', '["https://cdn.tuoitre.vn/thumb_w/480/2022/3/13/logo-dptrungnam7-1647141329088927871571.jpg"]', 3.2, 837, '07:00', '17:30', 0, '["bảo tồn","động vật","thực vật"]');
INSERT INTO `destinations` VALUES (299, 'Thung Nai', 'Thung Nai (Hòa Bình) là khu du lịch nổi tiếng với cảnh sắc thiên nhiên hùng vĩ, bao gồm hồ nước rộng lớn và các dãy núi bao quanh. Nơi đây là địa điểm lý tưởng cho du khách yêu thích du lịch sinh thái và tham gia các hoạt động ngoài trời như chèo thuyền.', 'Hòa Bình', 'Hòa Bình', 'Hòa Bình', 20.766, 105.186, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQYz1fmShZLDoqjX0N9o-8uDiP5fvlaUGP4Ow&s"]', 4.7, 777, '07:00', '17:00', 0, '["di sản","lịch sử","văn hóa"]');
INSERT INTO `destinations` VALUES (300, 'Mai Châu', 'Mai Châu (Hòa Bình) là một thung lũng xinh đẹp, nổi tiếng với những ngôi nhà sàn và cảnh sắc thiên nhiên hoang sơ. Mai Châu thu hút du khách bởi không khí trong lành, cộng với nền văn hóa đặc sắc của đồng bào dân tộc Thái.', 'Hòa Bình', 'Hòa Bình', 'Hòa Bình', 20.6599, 105.082, 'culture', '["https://vcdn1-dulich.vnecdn.net/2022/04/12/du-lich-Mai-Chau-thang-07-mobi-5431-9625-1649760588.jpg?w=0&h=0&q=100&dpr=1&fit=crop&s=5cITecmks1K0MS75q6iQnQ"]', 4.2, 635, '07:00', '17:00', 0, '["địa phương","độc đáo","khám phá"]');
INSERT INTO `destinations` VALUES (301, 'Động Đá Bạc', 'Động Đá Bạc (Quảng Ninh) là một hang động tự nhiên nổi bật với những khối đá vôi kỳ lạ và vẻ đẹp huyền bí. Du khách có thể khám phá hệ thống thạch nhũ và các tạo hình đá độc đáo trong không gian yên tĩnh của động.', 'Hòa Bình', 'Hòa Bình', 'Hòa Bình', 20.719, 105.185, 'nature', '["https://tour.dulichvietnam.com.vn/uploads/image/a-dia-danh-du-lich/dong-da-bac-1.jpg"]', 3.1, 1, '07:00', '17:00', 0, '["thiên nhiên","du lịch","hòa bình"]');
INSERT INTO `destinations` VALUES (302, 'Cửu thác Tú Sơn', 'Cửu thác Tú Sơn (Hà Giang) là một hệ thống 9 thác nước lớn nhỏ nằm giữa thiên nhiên hoang sơ. Đây là điểm đến lý tưởng cho những ai yêu thích khám phá và tìm hiểu các thác nước giữa không gian núi rừng.', 'Hòa Bình', 'Hòa Bình', 'Hòa Bình', 20.837783, 105.341237, 'nature', '["https://dulichbennghe.cdn.vccloud.vn/wp-content/uploads/2020/03/du-lich-ben-nghe-cuu-thac-tu-son.jpg"]', 3.7, 1, '07:00', '17:00', 0, '["cảnh quan","địa danh","nổi bật"]');
INSERT INTO `destinations` VALUES (303, 'Đền Thác Bờ', 'Đền Thác Bờ (Hòa Bình) là một di tích lịch sử, thờ nữ tướng Cao Thị Lịch. Đền nằm gần thác Bờ, có khung cảnh huyền bí và là nơi linh thiêng, thu hút du khách đến tham quan và cầu nguyện.', 'Hòa Bình', 'Hòa Bình', 'Hòa Bình', 20.741, 105.162, 'religious', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcShxh5UJa4Rwa6DjOg-8EmOofNkwvzf9QuAQA&s"]', 4.4, 756, '07:00', '18:00', 0, '["khám phá","thiên nhiên","thư giãn"]');
INSERT INTO `destinations` VALUES (304, 'Phố Hiến', 'Phố Hiến (Hưng Yên) là một khu phố cổ nổi tiếng với những công trình kiến trúc mang đậm dấu ấn lịch sử. Đây là một điểm đến hấp dẫn cho du khách muốn tìm hiểu về lịch sử, văn hóa và thưởng thức ẩm thực địa phương.', 'Hưng Yên', 'Hưng Yên', 'Hưng Yên', 20.646, 106.051, 'food', '["https://media.thanhtra.com.vn/public/data/images/0/2022/02/19/travan/pho%CC%82%CC%81-hie%CC%82%CC%81n-1.jpeg"]', 4, 620, '06:00', '22:00', 0, '["du lịch","thiên nhiên","cảnh đẹp"]');
INSERT INTO `destinations` VALUES (305, 'Chùa Chuông', 'Chùa Chuông (Hà Nội) là một ngôi chùa cổ có kiến trúc độc đáo, nằm trong khuôn viên rộng rãi, thanh tịnh. Đây là một địa điểm hành hương nổi tiếng, thu hút đông đảo phật tử và du khách đến tham quan.', 'Hưng Yên', 'Hưng Yên', 'Hưng Yên', 20.664411, 106.085692, 'beach', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTN_eID3pJlJkMN1b66P0GMq8yYTTUBj05Y6w&s"]', 4.3, 238, '00:00', '23:59', 0, '["lịch sử","văn hóa","khám phá"]');
INSERT INTO `destinations` VALUES (306, 'Làng nghề đúc đồng Lộng Thượng', 'Làng nghề đúc đồng Lộng Thượng (Hà Nội) nổi tiếng với nghề đúc đồng truyền thống từ lâu đời. Du khách có thể tham quan quy trình sản xuất các sản phẩm đồng thủ công mỹ nghệ và tìm hiểu về lịch sử làng nghề.', 'Hưng Yên', 'Hưng Yên', 'Hưng Yên', 20.604115, 106.035706, 'historical', '["https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSZBAnp--Ji_JlUPtWDWROIXwNRBCdT5cjONQ&s"]', 4.7, 302, '07:00', '17:00', 0, '["địa danh nổi tiếng","biểu tượng"]');
INSERT INTO `destinations` VALUES (307, 'Đền Phù Ủng', 'Đền Phù Ủng (Hưng Yên) là di tích lịch sử, thờ Đức thánh Phù Ủng, người có công giúp vua Hùng trong các cuộc chiến. Đền nằm trong khuôn viên rộng lớn, với không gian thanh tịnh và linh thiêng.', 'Hưng Yên', 'Hưng Yên', 'Hưng Yên', 20.693522, 106.031593, 'religious', '["https://s-aicmscdn.vietnamhoinhap.vn/vnhn-media/20/1/26/img_2020-01-26_1580004165.jpg"]', 4.6, 866, '07:00', '18:00', 0, '["thư giãn","yên bình","du lịch sinh thái"]');
INSERT INTO `destinations` VALUES (308, 'Đình làng Nôm', 'Đình làng Nôm (Hưng Yên) là một di tích văn hóa đặc sắc, nổi bật với kiến trúc cổ truyền và các hoạt động lễ hội dân gian. Đây là điểm đến thu hút du khách khám phá những giá trị văn hóa truyền thống.', 'Hưng Yên', 'Hưng Yên', 'Hưng Yên', 20.640056, 106.064692, 'historical', '["https://imagev3.vietnamplus.vn/w1000/Uploaded/2024/qfsqy/2022_11_04/dinh_lang_nom.JPG.webp"]', 3.2, 1, '07:00', '17:00', 0, '["bảo tồn","động vật","thực vật"]');
